--
-- Name: compute_solar_position(); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.compute_solar_position() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    lat CONSTANT DOUBLE PRECISION := 40.1672;
    lon CONSTANT DOUBLE PRECISION := -105.1019;
    ts_utc TIMESTAMP WITH TIME ZONE;
    y INT; m INT; d INT; h DOUBLE PRECISION;
    A INT; B INT; JD DOUBLE PRECISION; JC DOUBLE PRECISION;
    L0 DOUBLE PRECISION; M_deg DOUBLE PRECISION; M_rad DOUBLE PRECISION;
    C DOUBLE PRECISION; sun_true_lon DOUBLE PRECISION;
    omega DOUBLE PRECISION; sun_app_lon DOUBLE PRECISION;
    obliquity DOUBLE PRECISION; obliquity_corr DOUBLE PRECISION;
    sin_decl DOUBLE PRECISION; decl DOUBLE PRECISION; cos_decl DOUBLE PRECISION;
    y_eq DOUBLE PRECISION; L0_rad DOUBLE PRECISION; eqtime DOUBLE PRECISION;
    time_offset DOUBLE PRECISION; utc_minutes DOUBLE PRECISION;
    true_solar_time DOUBLE PRECISION; hour_angle DOUBLE PRECISION;
    ha_rad DOUBLE PRECISION; lat_rad DOUBLE PRECISION;
    cos_zenith DOUBLE PRECISION; zenith DOUBLE PRECISION;
    altitude DOUBLE PRECISION; sin_zenith DOUBLE PRECISION;
    cos_az DOUBLE PRECISION; azimuth DOUBLE PRECISION;
BEGIN
    ts_utc := NEW.ts AT TIME ZONE 'UTC';
    y := EXTRACT(YEAR FROM ts_utc);
    m := EXTRACT(MONTH FROM ts_utc);
    d := EXTRACT(DAY FROM ts_utc);
    h := EXTRACT(HOUR FROM ts_utc) + EXTRACT(MINUTE FROM ts_utc) / 60.0 + EXTRACT(SECOND FROM ts_utc) / 3600.0;

    IF m <= 2 THEN y := y - 1; m := m + 12; END IF;
    A := y / 100;
    B := 2 - A + A / 4;
    JD := FLOOR(365.25 * (y + 4716)) + FLOOR(30.6001 * (m + 1)) + d + h / 24.0 + B - 1524.5;
    JC := (JD - 2451545.0) / 36525.0;

    L0 := (280.46646 + JC * (36000.76983 + 0.0003032 * JC));
    L0 := L0 - FLOOR(L0 / 360) * 360;
    M_deg := (357.52911 + JC * (35999.05029 - 0.0001537 * JC));
    M_deg := M_deg - FLOOR(M_deg / 360) * 360;
    M_rad := RADIANS(M_deg);

    C := SIN(M_rad) * (1.914602 - JC * (0.004817 + 0.000014 * JC))
         + SIN(2 * M_rad) * (0.019993 - 0.000101 * JC)
         + SIN(3 * M_rad) * 0.000289;

    sun_true_lon := L0 + C;
    omega := 125.04 - 1934.136 * JC;
    sun_app_lon := sun_true_lon - 0.00569 - 0.00478 * SIN(RADIANS(omega));

    obliquity := 23.0 + (26.0 + (21.448 - JC * (46.815 + JC * (0.00059 - JC * 0.001813))) / 60.0) / 60.0;
    obliquity_corr := obliquity + 0.00256 * COS(RADIANS(omega));

    sin_decl := SIN(RADIANS(obliquity_corr)) * SIN(RADIANS(sun_app_lon));
    decl := ASIN(sin_decl);
    cos_decl := COS(decl);

    y_eq := TAN(RADIANS(obliquity_corr) / 2) * TAN(RADIANS(obliquity_corr) / 2);
    L0_rad := RADIANS(L0);
    eqtime := 4.0 * DEGREES(
        y_eq * SIN(2 * L0_rad)
        - 2.0 * 0.016708634 * SIN(M_rad)
        + 4.0 * 0.016708634 * y_eq * SIN(M_rad) * COS(2 * L0_rad)
        - 0.5 * y_eq * y_eq * SIN(4 * L0_rad)
        - 1.25 * 0.016708634 * 0.016708634 * SIN(2 * M_rad)
    );

    utc_minutes := h * 60.0;
    time_offset := eqtime + 4.0 * lon;
    true_solar_time := utc_minutes + time_offset;
    true_solar_time := true_solar_time - FLOOR(true_solar_time / 1440) * 1440;

    IF true_solar_time / 4.0 < 0 THEN
        hour_angle := true_solar_time / 4.0 + 180.0;
    ELSE
        hour_angle := true_solar_time / 4.0 - 180.0;
    END IF;
    ha_rad := RADIANS(hour_angle);

    lat_rad := RADIANS(lat);
    cos_zenith := SIN(lat_rad) * SIN(decl) + COS(lat_rad) * COS(decl) * COS(ha_rad);
    cos_zenith := GREATEST(-1.0, LEAST(1.0, cos_zenith));
    zenith := ACOS(cos_zenith);
    altitude := 90.0 - DEGREES(zenith);

    sin_zenith := SIN(zenith);
    IF ABS(sin_zenith) < 0.0000001 THEN
        azimuth := 180.0;
    ELSE
        cos_az := (SIN(decl) - SIN(lat_rad) * cos_zenith) / (COS(lat_rad) * sin_zenith);
        cos_az := GREATEST(-1.0, LEAST(1.0, cos_az));
        azimuth := DEGREES(ACOS(cos_az));
        IF hour_angle > 0 THEN azimuth := 360.0 - azimuth; END IF;
    END IF;

    NEW.solar_altitude_deg := ROUND(altitude::numeric, 2);
    NEW.solar_azimuth_deg := ROUND(azimuth::numeric, 2);
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.compute_solar_position() OWNER TO verdify;

--
-- Name: fn_band_setpoints(timestamp with time zone); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_band_setpoints(target_ts timestamp with time zone) RETURNS TABLE(temp_low double precision, temp_high double precision, vpd_low double precision, vpd_high double precision)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    local_hour int;
    frac float;
    next_hour int;
    h0_tl float; h0_th float; h0_vl float; h0_vh float;
    h1_tl float; h1_th float; h1_vl float; h1_vh float;
BEGIN
    local_hour := EXTRACT(hour FROM target_ts AT TIME ZONE 'America/Denver');
    frac := EXTRACT(minute FROM target_ts AT TIME ZONE 'America/Denver') / 60.0;
    next_hour := (local_hour + 1) % 24;

    SELECT MAX(temp_ideal_min), MIN(temp_ideal_max),
           MAX(vpd_ideal_min), MIN(vpd_ideal_max)
    INTO h0_tl, h0_th, h0_vl, h0_vh
    FROM crop_target_profiles
    WHERE hour_of_day = local_hour AND season = 'spring';

    SELECT MAX(temp_ideal_min), MIN(temp_ideal_max),
           MAX(vpd_ideal_min), MIN(vpd_ideal_max)
    INTO h1_tl, h1_th, h1_vl, h1_vh
    FROM crop_target_profiles
    WHERE hour_of_day = next_hour AND season = 'spring';

    temp_low  := h0_tl + frac * (h1_tl - h0_tl);
    temp_high := h0_th + frac * (h1_th - h0_th);
    vpd_low   := h0_vl + frac * (h1_vl - h0_vl);
    vpd_high  := h0_vh + frac * (h1_vh - h0_vh);
    RETURN NEXT;
END;
$$;


ALTER FUNCTION public.fn_band_setpoints(target_ts timestamp with time zone) OWNER TO verdify;

--
-- Name: fn_compliance_pct(interval); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_compliance_pct(lookback interval) RETURNS TABLE(zone text, temp_pct numeric, rh_pct numeric, vpd_pct numeric, overall_pct numeric)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    v.zone,
    ROUND(100.0 * COUNT(*) FILTER (WHERE temp_in_range) / NULLIF(COUNT(*), 0), 1) AS temp_pct,
    ROUND(100.0 * COUNT(*) FILTER (WHERE rh_in_range) / NULLIF(COUNT(*), 0), 1) AS rh_pct,
    ROUND(100.0 * COUNT(*) FILTER (WHERE vpd_in_range) / NULLIF(COUNT(*), 0), 1) AS vpd_pct,
    ROUND(100.0 * COUNT(*) FILTER (WHERE overall_compliant) / NULLIF(COUNT(*), 0), 1) AS overall_pct
  FROM v_setpoint_compliance v
  WHERE v.ts > now() - lookback
  GROUP BY v.zone
  ORDER BY v.zone;
$$;


ALTER FUNCTION public.fn_compliance_pct(lookback interval) OWNER TO verdify;

--
-- Name: FUNCTION fn_compliance_pct(lookback interval); Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON FUNCTION public.fn_compliance_pct(lookback interval) IS 'Returns compliance percentage per zone over the given interval. Example: SELECT * FROM fn_compliance_pct(interval ''24 hours'')';


--
-- Name: fn_current_season(); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_current_season() RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  RETURN CASE EXTRACT(MONTH FROM now())
    WHEN 3 THEN 'spring' WHEN 4 THEN 'spring' WHEN 5 THEN 'spring'
    WHEN 6 THEN 'summer' WHEN 7 THEN 'summer' WHEN 8 THEN 'summer'
    WHEN 9 THEN 'fall' WHEN 10 THEN 'fall' WHEN 11 THEN 'fall'
    ELSE 'winter'
  END;
END;
$$;


ALTER FUNCTION public.fn_current_season() OWNER TO verdify;

