--
-- Name: fn_equipment_health(); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_equipment_health() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    score INT := 100;
    rssi FLOAT;
    heap FLOAT;
    stuck_count INT;
    probe TEXT;
BEGIN
    SELECT wifi_rssi, heap_bytes, probe_health
    INTO rssi, heap, probe
    FROM diagnostics
    ORDER BY ts DESC LIMIT 1;

    -- WiFi deductions
    IF rssi IS NOT NULL THEN
        IF rssi < -85 THEN score := score - 25;
        ELSIF rssi < -75 THEN score := score - 10;
        END IF;
    END IF;

    -- Heap deductions (heap_bytes is stored in KB)
    IF heap IS NOT NULL THEN
        IF heap < 15 THEN score := score - 25;
        ELSIF heap < 30 THEN score := score - 10;
        END IF;
    END IF;

    -- Stuck relay deductions
    BEGIN
        SELECT COUNT(*) INTO stuck_count
        FROM v_relay_stuck
        WHERE is_stuck = TRUE;
        score := score - (stuck_count * 20);
    EXCEPTION WHEN undefined_table THEN
        NULL;
    END;

    -- Probe health deductions
    IF probe IS NOT NULL AND probe != 'OK' THEN
        score := score - 15;
    END IF;

    RETURN GREATEST(0, score);
END;
$$;


ALTER FUNCTION public.fn_equipment_health() OWNER TO verdify;

--
-- Name: fn_forecast_correction(text, numeric); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_forecast_correction(param text, lead_hours_max numeric DEFAULT 24) RETURNS TABLE(parameter text, avg_error numeric, samples bigint)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    param AS parameter,
    CASE param
      WHEN 'temp_f' THEN ROUND(AVG(temp_error)::numeric, 1)
      WHEN 'solar_w_m2' THEN ROUND(AVG(solar_error)::numeric, 0)
    END AS avg_error,
    count(*) AS samples
  FROM v_forecast_vs_actual
  WHERE hour > now() - interval '7 days'
  AND actual_temp IS NOT NULL
  AND EXTRACT(EPOCH FROM now() - hour) / 3600 <= lead_hours_max;
$$;


ALTER FUNCTION public.fn_forecast_correction(param text, lead_hours_max numeric) OWNER TO verdify;

--
-- Name: FUNCTION fn_forecast_correction(param text, lead_hours_max numeric); Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON FUNCTION public.fn_forecast_correction(param text, lead_hours_max numeric) IS 'Rolling 7-day forecast bias. Usage: SELECT * FROM fn_forecast_correction(''temp_f'', 24) → avg temp error for ≤24h forecasts.';


--
-- Name: fn_forecast_dli(date); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_forecast_dli(target_date date DEFAULT (CURRENT_DATE + 1)) RETURNS TABLE(predicted_dli numeric, gl_hours_needed numeric, recommended_gl_start integer, recommended_gl_end integer)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  POLY_DIRECT_TRANSMISSION CONSTANT float := 0.20;   -- frosted polycarbonate direct
  POLY_DIFFUSE_TRANSMISSION CONSTANT float := 0.25;   -- frosted polycarbonate diffuse
  UMOL_PER_W CONSTANT float := 2.02;                  -- PAR conversion (W/m² → µmol/m²/s)
  ACHIEVABLE_DLI_TARGET CONSTANT float := 10.0;       -- realistic target (not 14)
  GL_DLI_PER_HOUR CONSTANT float := 1.15;             -- grow light contribution (mol/m²/d per hour)
  -- Shadow window: house blocks before 11 AM local, trees block after 4 PM local
  SHADOW_START CONSTANT int := 11;  -- hour (local) house shadow clears
  SHADOW_END CONSTANT int := 16;    -- hour (local) tree shadow starts
BEGIN
  RETURN QUERY
  WITH hourly AS (
    SELECT DISTINCT ON (f.ts)
      EXTRACT(HOUR FROM f.ts AT TIME ZONE 'America/Denver')::int AS local_hour,
      f.direct_radiation_w_m2,
      f.diffuse_radiation_w_m2,
      f.sunshine_duration_s,
      -- Shadow factor: 0 if blocked, 1 if clear, partial for transition hours
      CASE
        WHEN EXTRACT(HOUR FROM f.ts AT TIME ZONE 'America/Denver') < SHADOW_START THEN 0.1  -- house shadow
        WHEN EXTRACT(HOUR FROM f.ts AT TIME ZONE 'America/Denver') >= SHADOW_END THEN 0.1   -- tree shadow
        ELSE 1.0  -- clear window
      END AS shadow_factor
    FROM weather_forecast f
    WHERE f.ts::date = target_date
    AND f.direct_radiation_w_m2 IS NOT NULL
    ORDER BY f.ts, f.fetched_at DESC
  ),
  dli_calc AS (
    SELECT SUM(
      (
        COALESCE(direct_radiation_w_m2, 0) * POLY_DIRECT_TRANSMISSION * shadow_factor
        + COALESCE(diffuse_radiation_w_m2, 0) * POLY_DIFFUSE_TRANSMISSION
      ) * UMOL_PER_W  -- µmol/m²/s indoor
      * COALESCE(sunshine_duration_s, 3600) / 1e6  -- convert to mol for this hour
    ) AS natural_dli
    FROM hourly
    WHERE direct_radiation_w_m2 > 0 OR diffuse_radiation_w_m2 > 0
  )
  SELECT
    ROUND(dc.natural_dli::numeric, 1) AS predicted_dli,
    ROUND(GREATEST(0, (ACHIEVABLE_DLI_TARGET - dc.natural_dli) / GL_DLI_PER_HOUR)::numeric, 1) AS gl_hours_needed,
    -- Recommend grow lights before shadow clears (morning fill) and after shadow falls (evening extend)
    7 AS recommended_gl_start,  -- 7 AM (before 11 AM shadow clear)
    19 AS recommended_gl_end    -- 7 PM (after 4 PM shadow fall)
  FROM dli_calc dc;
END;
$$;


ALTER FUNCTION public.fn_forecast_dli(target_date date) OWNER TO verdify;

--
-- Name: FUNCTION fn_forecast_dli(target_date date); Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON FUNCTION public.fn_forecast_dli(target_date date) IS 'Predict natural DLI from Open-Meteo forecast. Accounts for polycarbonate transmission (20% direct, 25% diffuse) and house/tree shadow window (11AM-4PM clear). Returns predicted DLI + grow light hours needed to reach 10 mol/m²/d.';


--
-- Name: fn_glazing_transmission(double precision); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_glazing_transmission(azimuth_deg double precision) RETURNS double precision
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT CASE
    WHEN azimuth_deg BETWEEN 210 AND 240 THEN 0.235  -- SW: best angle
    WHEN azimuth_deg BETWEEN 240 AND 300 THEN 0.200  -- West
    WHEN azimuth_deg BETWEEN 150 AND 210 THEN 0.149  -- South (solar noon)
    WHEN azimuth_deg BETWEEN 120 AND 150 THEN 0.084  -- SE
    WHEN azimuth_deg BETWEEN 60 AND 120  THEN 0.069  -- East (tree shadow)
    WHEN azimuth_deg < 60 OR azimuth_deg > 300 THEN 0.05  -- North-facing (minimal)
    ELSE 0.15  -- fallback average
  END;
$$;


ALTER FUNCTION public.fn_glazing_transmission(azimuth_deg double precision) OWNER TO verdify;

--
-- Name: fn_operational_health(); Type: FUNCTION; Schema: public; Owner: verdify
--

CREATE FUNCTION public.fn_operational_health() RETURNS jsonb
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    checks jsonb := '[]'::jsonb;
    total_score int := 0;
    max_score int := 105;
    v_ts timestamptz;
    v_age interval;
    v_count int;
    v_detail text;
    v_score int;
    v_date date;
BEGIN
    -- 1. Data freshness: climate row < 2min old = 10pts
    SELECT ts INTO v_ts FROM climate ORDER BY ts DESC LIMIT 1;
    v_age := now() - v_ts;
    IF v_ts IS NOT NULL AND v_age < interval '2 minutes' THEN
        v_score := 10;
        v_detail := format('Latest row %s ago', to_char(v_age, 'MI:SS'));
    ELSIF v_ts IS NOT NULL THEN
        v_score := 0;
        v_detail := format('Stale: last row %s ago', to_char(v_age, 'HH24:MI:SS'));
    ELSE
        v_score := 0;
        v_detail := 'No climate data';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'data_freshness', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 2. All 6 probes reporting = 10pts
    -- Probes: temp_north, temp_south, temp_east, temp_west, temp_intake, temp_case
    SELECT COUNT(*) INTO v_count
    FROM (
        SELECT 1 WHERE (SELECT temp_north FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT temp_south FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT temp_east FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT temp_west FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT temp_intake FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT temp_case FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
    ) probes;
    IF v_count = 6 THEN
        v_score := 10;
        v_detail := '6/6 probes reporting';
    ELSE
        v_score := 0;
        v_detail := format('%s/6 probes reporting', v_count);
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'probe_coverage', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 3. Ingestor liveness: most recent climate row < 5min (proxy for systemd active) = 10pts
    -- DB cannot check systemd directly; use data freshness as proxy
    IF v_ts IS NOT NULL AND (now() - v_ts) < interval '5 minutes' THEN
        v_score := 10;
        v_detail := 'Ingestor alive (data flowing)';
    ELSE
        v_score := 0;
        v_detail := 'Ingestor may be down (no recent data)';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'ingestor_liveness', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 4. Active plan: future waypoints > 0 = 10pts
    SELECT COUNT(*) INTO v_count
    FROM setpoint_plan
    WHERE is_active = true AND ts > now();
    IF v_count > 0 THEN
        v_score := 10;
        v_detail := format('%s future waypoints', v_count);
    ELSE
        v_score := 0;
        v_detail := 'No active future waypoints';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'active_plan', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 5. Dispatcher: last setpoint push < 10min = 10pts
    SELECT ts INTO v_ts FROM setpoint_changes ORDER BY ts DESC LIMIT 1;
    IF v_ts IS NOT NULL AND (now() - v_ts) < interval '10 minutes' THEN
        v_score := 10;
        v_detail := format('Last push %s ago', to_char(now() - v_ts, 'MI:SS'));
    ELSIF v_ts IS NOT NULL THEN
        v_score := 0;
        v_detail := format('Last push %s ago', to_char(now() - v_ts, 'HH24:MI:SS'));
    ELSE
        v_score := 0;
        v_detail := 'No setpoint changes recorded';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'dispatcher_active', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 6. Equipment assets populated = 5pts
    SELECT COUNT(*) INTO v_count FROM equipment_assets;
    IF v_count > 0 THEN
        v_score := 5;
        v_detail := format('%s assets registered', v_count);
    ELSE
        v_score := 0;
        v_detail := 'No equipment assets';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'equipment_assets', 'score', v_score, 'max', 5,
        'status', CASE WHEN v_score = 5 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 7. Nutrient recipes populated = 5pts
    SELECT COUNT(*) INTO v_count FROM nutrient_recipes;
    IF v_count > 0 THEN
        v_score := 5;
        v_detail := format('%s recipes defined', v_count);
    ELSE
        v_score := 0;
        v_detail := 'No nutrient recipes';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'nutrient_recipes', 'score', v_score, 'max', 5,
        'status', CASE WHEN v_score = 5 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 8. Active crops > 0 = 5pts
    SELECT COUNT(*) INTO v_count FROM crops WHERE is_active = true;
    IF v_count > 0 THEN
        v_score := 5;
        v_detail := format('%s active crops', v_count);
    ELSE
        v_score := 0;
        v_detail := 'No active crops';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'active_crops', 'score', v_score, 'max', 5,
        'status', CASE WHEN v_score = 5 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 9. No relay stuck alerts = 10pts
    BEGIN
        SELECT COUNT(*) INTO v_count FROM v_relay_stuck WHERE is_stuck = true;
        IF v_count = 0 THEN
            v_score := 10;
            v_detail := 'No stuck relays';
        ELSE
            v_score := 0;
            v_detail := format('%s stuck relay(s)', v_count);
        END IF;
    EXCEPTION WHEN undefined_table THEN
        v_score := 10;
        v_detail := 'Relay stuck view not available (assumed ok)';
    END;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'relay_health', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 10. Forecast data < 6h old = 10pts
    SELECT MAX(fetched_at) INTO v_ts FROM weather_forecast;
    IF v_ts IS NOT NULL AND (now() - v_ts) < interval '6 hours' THEN
        v_score := 10;
        v_detail := format('Forecast fetched %s ago', to_char(now() - v_ts, 'HH24:MI'));
    ELSIF v_ts IS NOT NULL THEN
        v_score := 0;
        v_detail := format('Forecast stale: fetched %s ago', to_char(now() - v_ts, 'HH24:MI'));
    ELSE
        v_score := 0;
        v_detail := 'No forecast data';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'forecast_freshness', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score = 10 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 11. Daily summary current = 5pts
    SELECT MAX(date) INTO v_date FROM daily_summary;
    IF v_date IS NOT NULL AND v_date >= (CURRENT_DATE - 1) THEN
        v_score := 5;
        v_detail := format('Latest summary: %s', v_date);
    ELSIF v_date IS NOT NULL THEN
        v_score := 0;
        v_detail := format('Summary stale: last %s', v_date);
    ELSE
        v_score := 0;
        v_detail := 'No daily summaries';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'daily_summary', 'score', v_score, 'max', 5,
        'status', CASE WHEN v_score = 5 THEN 'ok' ELSE 'fail' END, 'detail', v_detail);

    -- 12. Soil sensors reporting = 10pts
    -- Check soil_moisture_south_1, soil_moisture_south_2, soil_moisture_west from latest climate row
    SELECT COUNT(*) INTO v_count
    FROM (
        SELECT 1 WHERE (SELECT soil_moisture_south_1 FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT soil_moisture_south_2 FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
        UNION ALL
        SELECT 1 WHERE (SELECT soil_moisture_west FROM climate ORDER BY ts DESC LIMIT 1) IS NOT NULL
    ) soil;
    IF v_count = 3 THEN
        v_score := 10;
        v_detail := '3/3 soil sensors reporting';
    ELSIF v_count > 0 THEN
        v_score := 5;
        v_detail := format('%s/3 soil sensors reporting', v_count);
    ELSE
        v_score := 0;
        v_detail := 'No soil sensors reporting';
    END IF;
    total_score := total_score + v_score;
    checks := checks || jsonb_build_object(
        'name', 'soil_sensors', 'score', v_score, 'max', 10,
        'status', CASE WHEN v_score >= 10 THEN 'ok' WHEN v_score > 0 THEN 'degraded' ELSE 'fail' END, 'detail', v_detail);

    RETURN jsonb_build_object(
        'score', total_score,
        'max_score', max_score,
        'checks', checks
    );
END;
$$;


