--
-- Name: setpoint_plan; Type: TABLE; Schema: public; Owner: verdify
--

CREATE TABLE public.setpoint_plan (
    ts timestamp with time zone NOT NULL,
    parameter text NOT NULL,
    value double precision NOT NULL,
    plan_id text NOT NULL,
    source text DEFAULT 'iris'::text NOT NULL,
    reason text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    is_active boolean DEFAULT true,
    greenhouse_id text DEFAULT 'vallery'::text
);


ALTER TABLE public.setpoint_plan OWNER TO verdify;

--
-- Name: TABLE setpoint_plan; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON TABLE public.setpoint_plan IS 'AI-generated setpoint schedule. Iris writes future waypoints, dispatcher pushes to ESP32 via aioesphomeapi. Each row = "at time T, set parameter P to value V."';


--
-- Name: COLUMN setpoint_plan.ts; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.setpoint_plan.ts IS 'When this setpoint should take effect (UTC)';


--
-- Name: COLUMN setpoint_plan.parameter; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.setpoint_plan.parameter IS 'Matches setpoint_changes.parameter and ESP32 number entity names';


--
-- Name: COLUMN setpoint_plan.plan_id; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.setpoint_plan.plan_id IS 'Identifies which planning cycle generated this (e.g. 2026-03-24T07:00)';


--
-- Name: COLUMN setpoint_plan.reason; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.setpoint_plan.reason IS 'AI reasoning for this value (e.g. pre-cool for 95°F forecast)';


