-- Name: irrigation_log; Type: TABLE; Schema: public; Owner: verdify
--

CREATE TABLE public.irrigation_log (
    id integer NOT NULL,
    ts timestamp with time zone NOT NULL,
    zone text NOT NULL,
    schedule_id integer,
    scheduled_time time without time zone,
    actual_start timestamp with time zone NOT NULL,
    actual_end timestamp with time zone,
    volume_gal numeric(8,2),
    source text DEFAULT 'manual'::text NOT NULL,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT irrigation_log_source_check CHECK ((source = ANY (ARRAY['manual'::text, 'scheduled'::text, 'override'::text]))),
    CONSTRAINT irrigation_log_zone_check CHECK ((zone = ANY (ARRAY['south_wall'::text, 'west_wall'::text, 'center'::text, 'east_hydro'::text])))
);


