-- Name: TABLE irrigation_log; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON TABLE public.irrigation_log IS 'Actual irrigation events. Linked to schedule when triggered by automation, NULL schedule_id for manual runs. Hypertable partitioned on ts.';


