--
-- Name: climate; Type: TABLE; Schema: public; Owner: verdify
--

CREATE TABLE public.climate (
    ts timestamp with time zone NOT NULL,
    temp_avg double precision,
    temp_north double precision,
    temp_south double precision,
    temp_east double precision,
    temp_west double precision,
    temp_case double precision,
    temp_control double precision,
    temp_intake double precision,
    rh_avg double precision,
    rh_north double precision,
    rh_south double precision,
    rh_east double precision,
    rh_west double precision,
    rh_case double precision,
    vpd_avg double precision,
    vpd_north double precision,
    vpd_south double precision,
    vpd_east double precision,
    vpd_west double precision,
    vpd_control double precision,
    dew_point double precision,
    abs_humidity double precision,
    enthalpy_delta double precision,
    co2_ppm double precision,
    lux double precision,
    dli_today double precision,
    flow_gpm double precision,
    water_total_gal double precision,
    mister_water_today double precision,
    outdoor_temp_f double precision,
    outdoor_rh_pct double precision,
    ph_input double precision,
    ec_input double precision,
    ph_runoff_wall double precision,
    ec_runoff_wall double precision,
    ph_runoff_center double precision,
    ec_runoff_center double precision,
    moisture_north double precision,
    moisture_south double precision,
    moisture_center double precision,
    ppfd double precision,
    dli_par_today double precision,
    pressure_hpa double precision,
    leaf_temp_north double precision,
    leaf_temp_south double precision,
    leaf_wetness_north double precision,
    leaf_wetness_south double precision,
    wind_speed_mph double precision,
    wind_direction_deg double precision,
    outdoor_lux double precision,
    solar_irradiance_w_m2 double precision,
    precip_in double precision,
    uv_index double precision,
    hydro_tds_ppm double precision,
    hydro_water_temp_f double precision,
    wind_gust_mph double precision,
    wind_lull_mph double precision,
    wind_speed_avg_mph double precision,
    wind_direction_avg_deg double precision,
    feels_like_f double precision,
    wet_bulb_temp_f double precision,
    vapor_pressure_inhg double precision,
    air_density_kg_m3 double precision,
    precip_intensity_in_h double precision,
    lightning_count integer,
    lightning_avg_dist_mi double precision,
    solar_altitude_deg double precision,
    solar_azimuth_deg double precision,
    hydro_ec_us_cm double precision,
    hydro_orp_mv double precision,
    hydro_ph double precision,
    hydro_battery_pct double precision,
    soil_moisture_south_1 double precision,
    soil_temp_south_1 double precision,
    soil_ec_south_1 double precision,
    soil_moisture_south_2 double precision,
    soil_temp_south_2 double precision,
    soil_moisture_west double precision,
    soil_temp_west double precision,
    intake_rh double precision,
    intake_vpd double precision,
    outdoor_illuminance double precision,
    greenhouse_id text DEFAULT 'vallery'::text
);


ALTER TABLE public.climate OWNER TO verdify;

--
-- Name: COLUMN climate.solar_altitude_deg; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.climate.solar_altitude_deg IS 'Sun angle above horizon in degrees. 0=horizon, 90=zenith, negative=below horizon.';


--
-- Name: COLUMN climate.solar_azimuth_deg; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON COLUMN public.climate.solar_azimuth_deg IS 'Compass bearing of sun in degrees. 0=N, 90=E, 180=S, 270=W.';


