--
-- Name: _hyper_9_145_chunk; Type: TABLE; Schema: _timescaledb_internal; Owner: verdify
--

CREATE TABLE _timescaledb_internal._hyper_9_145_chunk (
    CONSTRAINT constraint_145 CHECK (((ts >= '2026-03-19 00:00:00+00'::timestamp with time zone) AND (ts < '2026-03-26 00:00:00+00'::timestamp with time zone)))
)
INHERITS (public.weather_station);


ALTER TABLE _timescaledb_internal._hyper_9_145_chunk OWNER TO verdify;

--
-- Name: _hyper_9_312_chunk; Type: TABLE; Schema: _timescaledb_internal; Owner: verdify
--

CREATE TABLE _timescaledb_internal._hyper_9_312_chunk (
    CONSTRAINT constraint_243 CHECK (((ts >= '2026-03-26 00:00:00+00'::timestamp with time zone) AND (ts < '2026-04-02 00:00:00+00'::timestamp with time zone)))
)
INHERITS (public.weather_station);


ALTER TABLE _timescaledb_internal._hyper_9_312_chunk OWNER TO verdify;

