--
-- Name: alert_log; Type: TABLE; Schema: public; Owner: verdify
--

CREATE TABLE public.alert_log (
    id integer NOT NULL,
    ts timestamp with time zone DEFAULT now() NOT NULL,
    alert_type text NOT NULL,
    severity text DEFAULT 'warning'::text NOT NULL,
    sensor_id text,
    zone text,
    message text NOT NULL,
    details jsonb,
    source text DEFAULT 'system'::text,
    disposition text DEFAULT 'open'::text NOT NULL,
    acknowledged_at timestamp with time zone,
    acknowledged_by text,
    resolved_at timestamp with time zone,
    resolved_by text,
    resolution text,
    slack_ts text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    category text DEFAULT 'system'::text NOT NULL,
    metric_value double precision,
    threshold_value double precision,
    notes text,
    greenhouse_id text DEFAULT 'vallery'::text,
    CONSTRAINT chk_alert_disposition CHECK ((disposition = ANY (ARRAY['open'::text, 'acknowledged'::text, 'resolved'::text, 'false_positive'::text, 'suppressed'::text]))),
