   FROM public.climate
  ORDER BY ts DESC
 LIMIT 1;


ALTER VIEW public.v_climate_latest OWNER TO verdify;

--
-- Name: v_climate_merged; Type: MATERIALIZED VIEW; Schema: public; Owner: verdify
--

CREATE MATERIALIZED VIEW public.v_climate_merged AS
 SELECT public.time_bucket('00:30:00'::interval, ts) AS bucket,
    avg(temp_avg) FILTER (WHERE (temp_avg IS NOT NULL)) AS temp_avg,
    avg(temp_north) FILTER (WHERE (temp_north IS NOT NULL)) AS temp_north,
    avg(temp_south) FILTER (WHERE (temp_south IS NOT NULL)) AS temp_south,
    avg(rh_avg) FILTER (WHERE (rh_avg IS NOT NULL)) AS rh_avg,
    avg(vpd_avg) FILTER (WHERE (vpd_avg IS NOT NULL)) AS vpd_avg,
    avg(co2_ppm) FILTER (WHERE (co2_ppm IS NOT NULL)) AS co2_ppm,
    avg(lux) FILTER (WHERE (lux IS NOT NULL)) AS lux,
    max(dli_today) FILTER (WHERE (dli_today IS NOT NULL)) AS dli_today,
    avg(outdoor_temp_f) FILTER (WHERE (outdoor_temp_f IS NOT NULL)) AS outdoor_temp_f,
    avg(outdoor_rh_pct) FILTER (WHERE (outdoor_rh_pct IS NOT NULL)) AS outdoor_rh_pct,
    avg(solar_irradiance_w_m2) FILTER (WHERE (solar_irradiance_w_m2 IS NOT NULL)) AS solar_w_m2,
    avg(solar_altitude_deg) FILTER (WHERE (solar_altitude_deg IS NOT NULL)) AS solar_alt,
    avg(solar_azimuth_deg) FILTER (WHERE (solar_azimuth_deg IS NOT NULL)) AS solar_az,
    avg(wind_speed_mph) FILTER (WHERE (wind_speed_mph IS NOT NULL)) AS wind_mph,
    avg(pressure_hpa) FILTER (WHERE (pressure_hpa IS NOT NULL)) AS pressure_hpa,
    avg(outdoor_lux) FILTER (WHERE (outdoor_lux IS NOT NULL)) AS outdoor_lux,
    avg(flow_gpm) FILTER (WHERE (flow_gpm IS NOT NULL)) AS flow_gpm,
    avg(enthalpy_delta) FILTER (WHERE (enthalpy_delta IS NOT NULL)) AS enthalpy_delta
   FROM public.climate
  GROUP BY (public.time_bucket('00:30:00'::interval, ts))
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.v_climate_merged OWNER TO verdify;

--
-- Name: v_cost_today; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_cost_today AS
 WITH today_start AS (
         SELECT (date_trunc('day'::text, (now() AT TIME ZONE 'America/Denver'::text)) AT TIME ZONE 'America/Denver'::text) AS ts
        ), events_with_next AS (
         SELECT e.equipment,
            e.state,
            e.ts,
            lead(e.ts) OVER (PARTITION BY e.equipment ORDER BY e.ts) AS next_ts
           FROM public.equipment_state e,
            today_start t
          WHERE (e.ts >= t.ts)
        ), runtimes AS (
         SELECT events_with_next.equipment,
            sum(
                CASE
                    WHEN (events_with_next.state = true) THEN (EXTRACT(epoch FROM (COALESCE(events_with_next.next_ts, now()) - events_with_next.ts)) / (3600)::numeric)
                    ELSE (0)::numeric
                END) AS hours_on
           FROM events_with_next
          GROUP BY events_with_next.equipment
        )
 SELECT round((COALESCE(sum(((((r.hours_on)::double precision * COALESCE(ea.wattage, (0)::double precision)) / (1000.0)::double precision) * (0.111)::double precision)), (0)::double precision))::numeric, 2) AS cost_electric,
    round(COALESCE(( SELECT (((r2.hours_on * 75000.0) / 100000.0) * 0.83)
           FROM runtimes r2
          WHERE (r2.equipment = 'heat2'::text)), (0)::numeric), 2) AS cost_gas,
    round((COALESCE(( SELECT ((max(c.water_total_gal) - min(c.water_total_gal)) * (0.00484)::double precision)
           FROM public.climate c,
            today_start t
          WHERE ((c.ts >= t.ts) AND (c.water_total_gal > (0)::double precision))), (0)::double precision))::numeric, 2) AS cost_water,
    round((((COALESCE(sum(((((r.hours_on)::double precision * COALESCE(ea.wattage, (0)::double precision)) / (1000.0)::double precision) * (0.111)::double precision)), (0)::double precision) + (COALESCE(( SELECT (((r2.hours_on * 75000.0) / 100000.0) * 0.83)
           FROM runtimes r2
          WHERE (r2.equipment = 'heat2'::text)), (0)::numeric))::double precision) + COALESCE(( SELECT ((max(c.water_total_gal) - min(c.water_total_gal)) * (0.00484)::double precision)
           FROM public.climate c,
            today_start t
          WHERE ((c.ts >= t.ts) AND (c.water_total_gal > (0)::double precision))), (0)::double precision)))::numeric, 2) AS cost_total
   FROM (runtimes r
     LEFT JOIN public.equipment_assets ea ON ((r.equipment = ea.equipment)));


ALTER VIEW public.v_cost_today OWNER TO verdify;

--
-- Name: v_crop_health_trend; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_crop_health_trend AS
 SELECT c.name AS crop_name,
    c.zone,
    (o.ts AT TIME ZONE 'America/Denver'::text) AS observed,
    o.health_score,
    o.obs_type AS observation_type,
    o.notes,
    o.source
   FROM (public.observations o
     JOIN public.crops c ON ((o.crop_id = c.id)))
  WHERE (o.ts > (now() - '30 days'::interval))
  ORDER BY c.name, o.ts DESC;


ALTER VIEW public.v_crop_health_trend OWNER TO verdify;

--
-- Name: v_daily_checklist; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_daily_checklist AS
 WITH last_done AS (
         SELECT daily_checklist_log.template_id,
            max(daily_checklist_log.date) FILTER (WHERE (daily_checklist_log.completed_at IS NOT NULL)) AS last_completed
           FROM public.daily_checklist_log
          GROUP BY daily_checklist_log.template_id
        )
 SELECT t.id AS template_id,
    t.task,
    t.zone,
    t.priority,
    t.frequency,
    t.role,
        CASE t.frequency
            WHEN 'daily'::text THEN true
            WHEN 'weekly'::text THEN ((ld.last_completed IS NULL) OR ((CURRENT_DATE - ld.last_completed) > 6))
            WHEN 'biweekly'::text THEN ((ld.last_completed IS NULL) OR ((CURRENT_DATE - ld.last_completed) > 13))
            WHEN 'monthly'::text THEN ((ld.last_completed IS NULL) OR ((CURRENT_DATE - ld.last_completed) > 29))
            ELSE NULL::boolean
        END AS is_due_today,
    ld.last_completed,
    log.completed_at,
    log.completed_by,
    log.skipped,
    log.skip_reason,
    log.notes AS log_notes
   FROM ((public.daily_checklist_template t
     LEFT JOIN last_done ld ON ((ld.template_id = t.id)))
     LEFT JOIN public.daily_checklist_log log ON (((log.template_id = t.id) AND (log.date = CURRENT_DATE))))
  WHERE (t.is_active = true)
  ORDER BY (log.completed_at IS NOT NULL), t.priority, t.zone;


ALTER VIEW public.v_daily_checklist OWNER TO verdify;

--
-- Name: VIEW v_daily_checklist; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_daily_checklist IS 'Today''s checklist: shows all active tasks, whether due today, completion status. Incomplete + due items sort first.';


--
-- Name: v_data_pipeline_health; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_data_pipeline_health AS
 SELECT 'climate'::text AS source,
    count(*) FILTER (WHERE (climate.ts > (now() - '01:00:00'::interval))) AS rows_1h,
    count(*) FILTER (WHERE (climate.ts > (now() - '24:00:00'::interval))) AS rows_24h,
    (EXTRACT(epoch FROM (now() - max(climate.ts))))::integer AS age_s,
    (((count(*) FILTER (WHERE ((climate.temp_avg IS NULL) AND (climate.ts > (now() - '01:00:00'::interval)))))::double precision / (NULLIF(count(*) FILTER (WHERE (climate.ts > (now() - '01:00:00'::interval))), 0))::double precision) * (100)::double precision) AS null_pct_1h
   FROM public.climate
UNION ALL
 SELECT 'equipment'::text AS source,
    count(*) FILTER (WHERE (equipment_state.ts > (now() - '01:00:00'::interval))) AS rows_1h,
    count(*) FILTER (WHERE (equipment_state.ts > (now() - '24:00:00'::interval))) AS rows_24h,
    (EXTRACT(epoch FROM (now() - max(equipment_state.ts))))::integer AS age_s,
    NULL::double precision AS null_pct_1h
   FROM public.equipment_state
UNION ALL
 SELECT 'diagnostics'::text AS source,
    count(*) FILTER (WHERE (diagnostics.ts > (now() - '01:00:00'::interval))) AS rows_1h,
    count(*) FILTER (WHERE (diagnostics.ts > (now() - '24:00:00'::interval))) AS rows_24h,
    (EXTRACT(epoch FROM (now() - max(diagnostics.ts))))::integer AS age_s,
    NULL::double precision AS null_pct_1h
   FROM public.diagnostics
UNION ALL
 SELECT 'energy'::text AS source,
    count(*) FILTER (WHERE (energy.ts > (now() - '01:00:00'::interval))) AS rows_1h,
    count(*) FILTER (WHERE (energy.ts > (now() - '24:00:00'::interval))) AS rows_24h,
    (EXTRACT(epoch FROM (now() - max(energy.ts))))::integer AS age_s,
    NULL::double precision AS null_pct_1h
   FROM public.energy
UNION ALL
 SELECT 'setpoints'::text AS source,
    count(*) FILTER (WHERE (setpoint_changes.ts > (now() - '01:00:00'::interval))) AS rows_1h,
    count(*) FILTER (WHERE (setpoint_changes.ts > (now() - '24:00:00'::interval))) AS rows_24h,
    (EXTRACT(epoch FROM (now() - max(setpoint_changes.ts))))::integer AS age_s,
    NULL::double precision AS null_pct_1h
   FROM public.setpoint_changes;


ALTER VIEW public.v_data_pipeline_health OWNER TO verdify;

--
-- Name: v_dew_point_risk; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_dew_point_risk AS
 SELECT (date_trunc('day'::text, ts))::date AS date,
    round((min((temp_avg - dew_point)))::numeric, 1) AS min_margin_f,
    round((avg((temp_avg - dew_point)))::numeric, 1) AS avg_margin_f,
    round((((count(*) FILTER (WHERE ((temp_avg - dew_point) < (5)::double precision)))::numeric * 2.0) / (60)::numeric), 1) AS risk_hours,
    round((((count(*) FILTER (WHERE ((temp_avg - dew_point) < (3)::double precision)))::numeric * 2.0) / (60)::numeric), 1) AS critical_hours
   FROM public.climate
  WHERE ((temp_avg IS NOT NULL) AND (dew_point IS NOT NULL))
  GROUP BY ((date_trunc('day'::text, ts))::date)
  ORDER BY ((date_trunc('day'::text, ts))::date);


ALTER VIEW public.v_dew_point_risk OWNER TO verdify;

--
-- Name: VIEW v_dew_point_risk; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_dew_point_risk IS 'Indoor condensation risk: dew point margin (temp_avg - dew_point). <5°F = risk, <3°F = imminent. Computed from ESP32 indoor sensors.';


--
-- Name: v_dif; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_dif AS
 SELECT date_trunc('day'::text, (ts AT TIME ZONE 'America/Denver'::text)) AS date,
    round((avg(
        CASE
            WHEN ((EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) >= (7)::numeric) AND (EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) <= (18)::numeric)) THEN temp_avg
            ELSE NULL::double precision
        END))::numeric, 2) AS day_avg_temp,
    round((avg(
        CASE
            WHEN ((EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) < (7)::numeric) OR (EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) > (18)::numeric)) THEN temp_avg
            ELSE NULL::double precision
        END))::numeric, 2) AS night_avg_temp,
    round(((avg(
        CASE
            WHEN ((EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) >= (7)::numeric) AND (EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) <= (18)::numeric)) THEN temp_avg
            ELSE NULL::double precision
        END) - avg(
        CASE
            WHEN ((EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) < (7)::numeric) OR (EXTRACT(hour FROM (ts AT TIME ZONE 'America/Denver'::text)) > (18)::numeric)) THEN temp_avg
            ELSE NULL::double precision
        END)))::numeric, 2) AS dif
   FROM public.climate
  WHERE (temp_avg IS NOT NULL)
  GROUP BY (date_trunc('day'::text, (ts AT TIME ZONE 'America/Denver'::text)))
  ORDER BY (date_trunc('day'::text, (ts AT TIME ZONE 'America/Denver'::text)));


ALTER VIEW public.v_dif OWNER TO verdify;

--
-- Name: v_disease_risk; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_disease_risk AS
 WITH recent AS (
         SELECT climate.ts,
            climate.rh_avg,
            climate.temp_avg,
            climate.vpd_avg
           FROM public.climate
          WHERE ((climate.ts >= (now() - '24:00:00'::interval)) AND (climate.rh_avg IS NOT NULL) AND (climate.temp_avg IS NOT NULL))
        ), botrytis_windows AS (
         SELECT recent.ts,
                CASE
                    WHEN ((recent.rh_avg > (85)::double precision) AND ((recent.temp_avg >= (60)::double precision) AND (recent.temp_avg <= (80)::double precision))) THEN 1
                    ELSE 0
                END AS botrytis_flag,
                CASE
                    WHEN (recent.vpd_avg < (0.4)::double precision) THEN 1
                    ELSE 0
                END AS condensation_flag
           FROM recent
        )
 SELECT date_trunc('hour'::text, ts) AS hour,
    round((avg(botrytis_flag) * (100)::numeric), 1) AS botrytis_risk_pct,
    round((avg(condensation_flag) * (100)::numeric), 1) AS condensation_risk_pct,
    round((((sum(botrytis_flag))::numeric * 2.0) / 60.0), 2) AS botrytis_consecutive_hours,
    round((((sum(condensation_flag))::numeric * 2.0) / 60.0), 2) AS condensation_consecutive_hours
   FROM botrytis_windows
  GROUP BY (date_trunc('hour'::text, ts))
  ORDER BY (date_trunc('hour'::text, ts));


ALTER VIEW public.v_disease_risk OWNER TO verdify;

--
-- Name: v_equipment_now; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_equipment_now AS
 SELECT DISTINCT ON (equipment) equipment,
    state,
    ts AS since,
    round(EXTRACT(epoch FROM (now() - ts))) AS seconds_ago
   FROM public.equipment_state
  ORDER BY equipment, ts DESC;


ALTER VIEW public.v_equipment_now OWNER TO verdify;

--
-- Name: v_equipment_runtime_daily; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_equipment_runtime_daily AS
 WITH transitions AS (
         SELECT ((equipment_state.ts AT TIME ZONE 'America/Denver'::text))::date AS day,
            equipment_state.equipment,
            equipment_state.ts,
            equipment_state.state,
            lead(equipment_state.ts) OVER (PARTITION BY equipment_state.equipment, (((equipment_state.ts AT TIME ZONE 'America/Denver'::text))::date) ORDER BY equipment_state.ts) AS next_ts
           FROM public.equipment_state
          WHERE (equipment_state.equipment = ANY (ARRAY['fan1'::text, 'fan2'::text, 'heat1'::text, 'heat2'::text, 'fog'::text, 'vent'::text, 'mister_south'::text, 'mister_west'::text, 'mister_center'::text, 'grow_light_main'::text, 'grow_light_grow'::text, 'drip_wall'::text, 'drip_center'::text]))
        )
 SELECT day,
    equipment,
    round(sum((EXTRACT(epoch FROM (COALESCE(next_ts, (((day + 1))::timestamp without time zone AT TIME ZONE 'America/Denver'::text)) - ts)) / 60.0)) FILTER (WHERE (state = true)), 1) AS on_minutes,
    count(*) FILTER (WHERE (state = true)) AS cycles
   FROM transitions
  GROUP BY day, equipment;


ALTER VIEW public.v_equipment_runtime_daily OWNER TO verdify;

--
-- Name: v_equipment_runtime_today; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_equipment_runtime_today AS
 SELECT equipment,
    sum(
        CASE
            WHEN (state = true) THEN 1
            ELSE 0
        END) AS on_events,
    sum(
        CASE
            WHEN (state = false) THEN 1
            ELSE 0
        END) AS off_events
   FROM public.equipment_state
  WHERE (ts >= date_trunc('day'::text, now()))
  GROUP BY equipment;


ALTER VIEW public.v_equipment_runtime_today OWNER TO verdify;

--
-- Name: v_estimated_dli; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_estimated_dli AS
 WITH readings AS (
         SELECT climate.ts,
            (date_trunc('day'::text, (climate.ts AT TIME ZONE 'America/Denver'::text)))::date AS date,
            ((climate.outdoor_lux * public.fn_glazing_transmission(climate.solar_azimuth_deg)) * (0.0185)::double precision) AS ppfd,
            COALESCE(EXTRACT(epoch FROM (lead(climate.ts) OVER (PARTITION BY ((date_trunc('day'::text, (climate.ts AT TIME ZONE 'America/Denver'::text)))::date) ORDER BY climate.ts) - climate.ts)), (300)::numeric) AS dt_sec
           FROM public.climate
          WHERE ((climate.outdoor_lux > (0)::double precision) AND (climate.solar_azimuth_deg IS NOT NULL) AND (climate.solar_altitude_deg > (0)::double precision))
        )
 SELECT date,
    round(((sum((ppfd * (LEAST(dt_sec, (900)::numeric))::double precision)) / (1000000)::double precision))::numeric, 1) AS est_natural_dli,
    count(*) AS readings
   FROM readings
  WHERE ((dt_sec > (0)::numeric) AND (dt_sec < (900)::numeric))
  GROUP BY date
  ORDER BY date;


ALTER VIEW public.v_estimated_dli OWNER TO verdify;

--
-- Name: v_estimated_indoor_light; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_estimated_indoor_light AS
 SELECT public.time_bucket('00:15:00'::interval, ts) AS bucket,
    round((avg((outdoor_lux * public.fn_glazing_transmission(solar_azimuth_deg))))::numeric, 0) AS est_indoor_lux,
    round((avg(((outdoor_lux * public.fn_glazing_transmission(solar_azimuth_deg)) * (0.0185)::double precision)))::numeric, 1) AS est_ppfd,
    round((avg(solar_altitude_deg))::numeric, 1) AS sun_altitude,
    round((avg(outdoor_lux))::numeric, 0) AS outdoor_lux,
    round((avg((public.fn_glazing_transmission(solar_azimuth_deg) * (100)::double precision)))::numeric, 1) AS transmission_pct
   FROM public.climate
  WHERE ((outdoor_lux > (0)::double precision) AND (solar_azimuth_deg IS NOT NULL) AND (solar_altitude_deg > (0)::double precision))
  GROUP BY (public.time_bucket('00:15:00'::interval, ts))
  ORDER BY (public.time_bucket('00:15:00'::interval, ts));


ALTER VIEW public.v_estimated_indoor_light OWNER TO verdify;

--
-- Name: v_estimated_plant_dli; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_estimated_plant_dli AS
 SELECT date,
    round((COALESCE(dli_final, (0)::double precision))::numeric, 1) AS sensor_dli,
    round(((COALESCE(dli_final, (0)::double precision) * (3.5)::double precision))::numeric, 1) AS corrected_solar_dli,
    round(((COALESCE(runtime_grow_light_min, (0)::double precision) / (60.0)::double precision))::numeric, 1) AS grow_light_hours,
    round((((COALESCE(runtime_grow_light_min, (0)::double precision) / (60.0)::double precision) * (0.8)::double precision))::numeric, 1) AS grow_light_dli,
    round((((COALESCE(dli_final, (0)::double precision) * (3.5)::double precision) + ((COALESCE(runtime_grow_light_min, (0)::double precision) / (60.0)::double precision) * (0.8)::double precision)))::numeric, 1) AS estimated_plant_dli,
        CASE
            WHEN (((COALESCE(dli_final, (0)::double precision) * (3.5)::double precision) + ((COALESCE(runtime_grow_light_min, (0)::double precision) / (60.0)::double precision) * (0.8)::double precision)) < (12)::double precision) THEN 'LOW'::text
            WHEN (((COALESCE(dli_final, (0)::double precision) * (3.5)::double precision) + ((COALESCE(runtime_grow_light_min, (0)::double precision) / (60.0)::double precision) * (0.8)::double precision)) > (30)::double precision) THEN 'HIGH'::text
            ELSE 'OK'::text
        END AS dli_status
   FROM public.daily_summary ds
  ORDER BY date DESC;


ALTER VIEW public.v_estimated_plant_dli OWNER TO verdify;

--
-- Name: VIEW v_estimated_plant_dli; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_estimated_plant_dli IS 'Estimated actual plant DLI: sensor × 3.5 correction + grow light hours × 0.8 mol/hr. LOW<12, OK=12-30, HIGH>30.';


--
-- Name: v_exterior_vpd; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_exterior_vpd AS
 SELECT ts,
        CASE
            WHEN ((outdoor_temp_f IS NOT NULL) AND (outdoor_rh_pct IS NOT NULL)) THEN round(((((0.6108)::double precision * exp((((17.27)::double precision * (((outdoor_temp_f - (32)::double precision) * (5.0)::double precision) / (9.0)::double precision)) / ((((outdoor_temp_f - (32)::double precision) * (5.0)::double precision) / (9.0)::double precision) + (237.3)::double precision)))) * ((1)::double precision - (outdoor_rh_pct / (100.0)::double precision))))::numeric, 3)
            ELSE NULL::numeric
        END AS exterior_vpd_kpa
   FROM public.climate
  WHERE (outdoor_temp_f IS NOT NULL);


ALTER VIEW public.v_exterior_vpd OWNER TO verdify;

--
-- Name: v_forecast_accuracy; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_forecast_accuracy AS
 SELECT f.ts AS forecast_hour,
    f.fetched_at,
    round((EXTRACT(epoch FROM (f.ts - f.fetched_at)) / (3600)::numeric), 1) AS lead_hours,
    f.temp_f AS forecast_temp,
    m.outdoor_temp_f AS actual_temp,
    round(((f.temp_f - m.outdoor_temp_f))::numeric, 1) AS temp_error_f,
    f.vpd_kpa AS forecast_vpd,
    m.vpd_avg AS actual_vpd,
    round(((f.vpd_kpa - m.vpd_avg))::numeric, 2) AS vpd_error_kpa,
    f.solar_w_m2 AS forecast_solar,
    m.solar_w_m2 AS actual_solar,
    round(((f.solar_w_m2 - m.solar_w_m2))::numeric, 1) AS solar_error_w
   FROM (public.weather_forecast f
     JOIN public.v_climate_merged m ON ((public.time_bucket('01:00:00'::interval, m.bucket) = f.ts)))
  WHERE (f.ts < now());


ALTER VIEW public.v_forecast_accuracy OWNER TO verdify;

--
-- Name: VIEW v_forecast_accuracy; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_forecast_accuracy IS 'Forecast vs actual comparison. Uses outdoor_temp_f (not indoor). lead_hours = how far ahead the forecast was made.';


--
-- Name: v_forecast_accuracy_daily; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_forecast_accuracy_daily AS
 WITH forecast_deduped AS (
         SELECT DISTINCT ON (weather_forecast.ts) weather_forecast.ts,
            weather_forecast.fetched_at,
            weather_forecast.temp_f,
            weather_forecast.rh_pct,
            weather_forecast.cloud_cover_pct
           FROM public.weather_forecast
          WHERE ((weather_forecast.ts >= (now() - '14 days'::interval)) AND (weather_forecast.ts <= now()))
          ORDER BY weather_forecast.ts, weather_forecast.fetched_at DESC
        ), forecast_daily AS (
         SELECT (date_trunc('day'::text, forecast_deduped.ts))::date AS date,
            avg(forecast_deduped.temp_f) AS fc_temp_avg,
            avg(forecast_deduped.rh_pct) AS fc_rh_avg,
            avg(forecast_deduped.cloud_cover_pct) AS fc_cloud_avg,
            avg((EXTRACT(epoch FROM (forecast_deduped.ts - forecast_deduped.fetched_at)) / 3600.0)) AS horizon_hours
           FROM forecast_deduped
          GROUP BY ((date_trunc('day'::text, forecast_deduped.ts))::date)
        ), observed_daily AS (
         SELECT (date_trunc('day'::text, climate.ts))::date AS date,
            avg(climate.outdoor_temp_f) AS obs_temp_avg,
            avg(climate.outdoor_rh_pct) AS obs_rh_avg
           FROM public.climate
          WHERE ((climate.ts >= (now() - '14 days'::interval)) AND (climate.ts <= now()))
          GROUP BY ((date_trunc('day'::text, climate.ts))::date)
        )
 SELECT f.date,
    p.param,
        CASE p.param
            WHEN 'temp_f'::text THEN f.fc_temp_avg
            WHEN 'rh_pct'::text THEN f.fc_rh_avg
            WHEN 'cloud_cover_pct'::text THEN f.fc_cloud_avg
            ELSE NULL::double precision
        END AS forecast_avg,
        CASE p.param
            WHEN 'temp_f'::text THEN o.obs_temp_avg
            WHEN 'rh_pct'::text THEN o.obs_rh_avg
            WHEN 'cloud_cover_pct'::text THEN NULL::double precision
            ELSE NULL::double precision
        END AS observed_avg,
        CASE p.param
            WHEN 'temp_f'::text THEN (f.fc_temp_avg - o.obs_temp_avg)
            WHEN 'rh_pct'::text THEN (f.fc_rh_avg - o.obs_rh_avg)
            WHEN 'cloud_cover_pct'::text THEN NULL::double precision
            ELSE NULL::double precision
        END AS bias,
        CASE p.param
            WHEN 'temp_f'::text THEN abs((f.fc_temp_avg - o.obs_temp_avg))
            WHEN 'rh_pct'::text THEN abs((f.fc_rh_avg - o.obs_rh_avg))
            WHEN 'cloud_cover_pct'::text THEN NULL::double precision
            ELSE NULL::double precision
        END AS abs_error,
    round(f.horizon_hours, 1) AS horizon_hours
   FROM ((forecast_daily f
     JOIN observed_daily o USING (date))
     CROSS JOIN ( VALUES ('temp_f'::text), ('rh_pct'::text), ('cloud_cover_pct'::text)) p(param))
  ORDER BY f.date DESC, p.param;


ALTER VIEW public.v_forecast_accuracy_daily OWNER TO verdify;

--
-- Name: v_forecast_actions_recent; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_forecast_actions_recent AS
 SELECT (triggered_at AT TIME ZONE 'America/Denver'::text) AS triggered,
    rule_name,
    action_taken,
    param,
    old_value,
    new_value,
    plan_id,
    (forecast_condition ->> 'trigger_value'::text) AS trigger_value,
    (forecast_condition ->> 'trigger_hour'::text) AS trigger_hour,
    outcome
   FROM public.forecast_action_log fl
  WHERE (triggered_at > (now() - '7 days'::interval))
  ORDER BY triggered_at DESC;


ALTER VIEW public.v_forecast_actions_recent OWNER TO verdify;

--
-- Name: v_forecast_latest; Type: VIEW; Schema: public; Owner: verdify
