ALTER VIEW public.v_forecast_latest OWNER TO verdify;

--
-- Name: VIEW v_forecast_latest; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_forecast_latest IS 'Most recent forecast for each hour. Use instead of weather_forecast directly.';


--
-- Name: v_forecast_vs_actual; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_forecast_vs_actual AS
 SELECT DISTINCT ON (f.ts) f.ts AS hour,
    round((f.temp_f)::numeric, 1) AS forecast_temp,
    round((f.rh_pct)::numeric, 0) AS forecast_rh,
    round((f.vpd_kpa)::numeric, 2) AS forecast_vpd,
    round((f.solar_w_m2)::numeric, 0) AS forecast_solar,
    round((c.outdoor_temp)::numeric, 1) AS actual_temp,
    round((c.outdoor_rh)::numeric, 0) AS actual_rh,
    round((c.solar)::numeric, 0) AS actual_solar,
    round(((f.temp_f - c.outdoor_temp))::numeric, 1) AS temp_error,
    round(((f.solar_w_m2 - c.solar))::numeric, 0) AS solar_error
   FROM (public.weather_forecast f
     LEFT JOIN LATERAL ( SELECT avg(climate.outdoor_temp_f) AS outdoor_temp,
            avg(climate.outdoor_rh_pct) AS outdoor_rh,
            avg(climate.solar_irradiance_w_m2) AS solar
           FROM public.climate
          WHERE ((climate.ts >= f.ts) AND (climate.ts < (f.ts + '01:00:00'::interval)) AND (climate.outdoor_temp_f IS NOT NULL))) c ON (true))
  WHERE ((f.ts < now()) AND (f.ts > (now() - '7 days'::interval)))
  ORDER BY f.ts, f.fetched_at DESC;


ALTER VIEW public.v_forecast_vs_actual OWNER TO verdify;

--
-- Name: VIEW v_forecast_vs_actual; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_forecast_vs_actual IS 'Hourly Open-Meteo forecast vs actual outdoor conditions. temp_error/solar_error show systematic forecast bias.';


--
-- Name: v_gdd; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_gdd AS
 WITH daily_temps AS (
         SELECT date_trunc('day'::text, climate.ts) AS date,
            avg(climate.temp_avg) AS avg_temp_f
           FROM public.climate
          WHERE (climate.temp_avg IS NOT NULL)
          GROUP BY (date_trunc('day'::text, climate.ts))
        )
 SELECT c.id AS crop_id,
    c.name,
    c."position",
    dt.date,
    GREATEST((0)::double precision, (dt.avg_temp_f - c.base_temp_f)) AS gdd_day,
    sum(GREATEST((0)::double precision, (dt.avg_temp_f - c.base_temp_f))) OVER (PARTITION BY c.id ORDER BY dt.date ROWS UNBOUNDED PRECEDING) AS gdd_cumulative
   FROM (public.crops c
     JOIN daily_temps dt ON ((dt.date >= (c.planted_date)::timestamp with time zone)))
  WHERE (c.is_active = true)
  ORDER BY c.id, dt.date;


ALTER VIEW public.v_gdd OWNER TO verdify;

--
-- Name: v_greenhouse_now; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_greenhouse_now AS
 SELECT c.ts,
    round((c.temp_avg)::numeric, 1) AS temp_avg,
    round((c.temp_north)::numeric, 1) AS temp_north,
    round((c.temp_south)::numeric, 1) AS temp_south,
    round((c.temp_east)::numeric, 1) AS temp_east,
    round((c.temp_west)::numeric, 1) AS temp_west,
    round((c.rh_avg)::numeric, 1) AS rh_avg,
    round((c.vpd_avg)::numeric, 2) AS vpd_avg,
    round((c.co2_ppm)::numeric, 0) AS co2_ppm,
    round((c.lux)::numeric, 0) AS lux,
    round((c.dli_today)::numeric, 2) AS dli_today,
    o.outdoor_temp_f,
    o.outdoor_rh_pct,
    o.wind_mph,
    o.pressure_hpa,
    round((c.mister_water_today)::numeric, 1) AS mister_water_today,
    h.hydro_ph,
    h.hydro_ec_us_cm,
    h.hydro_tds_ppm,
    h.hydro_water_temp_f,
    d.wifi_rssi,
    round((d.heap_bytes)::numeric, 0) AS heap_kb,
    round((d.uptime_s)::numeric, 0) AS uptime_s,
    ( SELECT system_state.value
           FROM public.system_state
          WHERE (system_state.entity = 'greenhouse_state'::text)
          ORDER BY system_state.ts DESC
         LIMIT 1) AS state,
    ( SELECT system_state.value
           FROM public.system_state
          WHERE (system_state.entity = 'lead_fan'::text)
          ORDER BY system_state.ts DESC
         LIMIT 1) AS lead_fan,
    public.fn_system_health() AS health_score,
    ( SELECT count(*) AS count
           FROM public.alert_log
          WHERE (alert_log.disposition = 'open'::text)) AS open_alerts,
    cost.cost_electric,
    cost.cost_gas,
    cost.cost_water,
    cost.cost_total
   FROM ((((public.climate c
     LEFT JOIN LATERAL ( SELECT diagnostics.wifi_rssi,
            diagnostics.heap_bytes,
            diagnostics.uptime_s
           FROM public.diagnostics
          ORDER BY diagnostics.ts DESC
         LIMIT 1) d ON (true))
     LEFT JOIN LATERAL ( SELECT round((climate.outdoor_temp_f)::numeric, 1) AS outdoor_temp_f,
            round((climate.outdoor_rh_pct)::numeric, 0) AS outdoor_rh_pct,
            round((climate.wind_speed_mph)::numeric, 1) AS wind_mph,
            round((climate.pressure_hpa)::numeric, 1) AS pressure_hpa
           FROM public.climate
          WHERE ((climate.outdoor_temp_f IS NOT NULL) AND (climate.ts > (now() - '00:30:00'::interval)))
          ORDER BY climate.ts DESC
         LIMIT 1) o ON (true))
     LEFT JOIN LATERAL ( SELECT round((climate.hydro_ph)::numeric, 1) AS hydro_ph,
            round((climate.hydro_ec_us_cm)::numeric, 0) AS hydro_ec_us_cm,
            round((climate.hydro_tds_ppm)::numeric, 0) AS hydro_tds_ppm,
            round((climate.hydro_water_temp_f)::numeric, 1) AS hydro_water_temp_f
           FROM public.climate
          WHERE ((climate.hydro_ph IS NOT NULL) AND (climate.ts > (now() - '00:30:00'::interval)))
          ORDER BY climate.ts DESC
         LIMIT 1) h ON (true))
     CROSS JOIN public.v_cost_today cost)
  WHERE (c.temp_avg IS NOT NULL)
  ORDER BY c.ts DESC
 LIMIT 1;


ALTER VIEW public.v_greenhouse_now OWNER TO verdify;

--
-- Name: v_hydro_status; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_hydro_status AS
 SELECT ts,
    round((hydro_ph)::numeric, 1) AS ph,
    round((hydro_ec_us_cm)::numeric, 0) AS ec_us_cm,
    round((hydro_tds_ppm)::numeric, 0) AS tds_ppm,
    round((hydro_orp_mv)::numeric, 0) AS orp_mv,
    round((hydro_water_temp_f)::numeric, 1) AS water_temp_f,
    round((hydro_battery_pct)::numeric, 0) AS battery_pct,
    ((hydro_ph >= (5.5)::double precision) AND (hydro_ph <= (6.5)::double precision)) AS ph_in_range,
    ((hydro_ec_us_cm >= (800)::double precision) AND (hydro_ec_us_cm <= (2000)::double precision)) AS ec_in_range,
    ((hydro_water_temp_f >= (60)::double precision) AND (hydro_water_temp_f <= (75)::double precision)) AS temp_in_range,
    (hydro_battery_pct > (20)::double precision) AS battery_ok
   FROM public.climate c
  WHERE (hydro_ph IS NOT NULL)
  ORDER BY ts DESC
 LIMIT 1;


ALTER VIEW public.v_hydro_status OWNER TO verdify;

--
-- Name: v_indoor_outdoor_correlation; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_indoor_outdoor_correlation AS
 SELECT public.time_bucket('01:00:00'::interval, ts) AS hour,
    round((avg(temp_avg))::numeric, 1) AS indoor_temp,
    round((avg(outdoor_temp_f))::numeric, 1) AS outdoor_temp,
    round(((avg(temp_avg) - avg(outdoor_temp_f)))::numeric, 1) AS thermal_gain,
    round((avg(solar_irradiance_w_m2))::numeric, 0) AS solar_w_m2,
    round((avg(vpd_avg))::numeric, 2) AS indoor_vpd,
    round((avg(outdoor_rh_pct))::numeric, 0) AS outdoor_rh,
    round((avg(wind_speed_mph))::numeric, 1) AS wind_mph,
        CASE
            WHEN (avg(solar_irradiance_w_m2) > (50)::double precision) THEN round(((((avg(temp_avg) - avg(outdoor_temp_f)) / NULLIF(avg(solar_irradiance_w_m2), (0)::double precision)) * (100)::double precision))::numeric, 2)
            ELSE NULL::numeric
        END AS gain_per_100w,
    count(*) AS samples
   FROM public.climate
  WHERE ((temp_avg IS NOT NULL) AND (outdoor_temp_f IS NOT NULL))
  GROUP BY (public.time_bucket('01:00:00'::interval, ts))
  ORDER BY (public.time_bucket('01:00:00'::interval, ts)) DESC;


ALTER VIEW public.v_indoor_outdoor_correlation OWNER TO verdify;

--
-- Name: VIEW v_indoor_outdoor_correlation; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_indoor_outdoor_correlation IS 'Hourly indoor vs outdoor temperature correlation. thermal_gain = indoor - outdoor. gain_per_100w = thermal gain coefficient per 100 W/m² solar load.';


--
-- Name: v_sensor_staleness; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_sensor_staleness AS
 WITH last_readings AS (
         SELECT sr.sensor_id,
            sr.type,
            sr.zone,
            sr.expected_interval_s,
            sr.source_table,
            sr.source_column,
                CASE sr.source_table
                    WHEN 'climate'::text THEN ( SELECT max(c.ts) AS max
                       FROM public.climate c
                      WHERE ((c.ts > (now() - GREATEST('02:00:00'::interval, ((sr.expected_interval_s)::double precision * '00:00:02'::interval)))) AND (
                            CASE sr.source_column
                                WHEN 'temp_avg'::text THEN c.temp_avg
                                WHEN 'temp_north'::text THEN c.temp_north
                                WHEN 'temp_south'::text THEN c.temp_south
                                WHEN 'temp_east'::text THEN c.temp_east
                                WHEN 'temp_west'::text THEN c.temp_west
                                WHEN 'temp_case'::text THEN c.temp_case
                                WHEN 'temp_control'::text THEN c.temp_control
                                WHEN 'temp_intake'::text THEN c.temp_intake
                                WHEN 'rh_avg'::text THEN c.rh_avg
                                WHEN 'rh_north'::text THEN c.rh_north
                                WHEN 'rh_south'::text THEN c.rh_south
                                WHEN 'rh_east'::text THEN c.rh_east
                                WHEN 'rh_west'::text THEN c.rh_west
                                WHEN 'rh_case'::text THEN c.rh_case
                                WHEN 'vpd_avg'::text THEN c.vpd_avg
                                WHEN 'vpd_north'::text THEN c.vpd_north
                                WHEN 'vpd_south'::text THEN c.vpd_south
                                WHEN 'vpd_east'::text THEN c.vpd_east
                                WHEN 'vpd_west'::text THEN c.vpd_west
                                WHEN 'vpd_control'::text THEN c.vpd_control
                                WHEN 'co2_ppm'::text THEN c.co2_ppm
                                WHEN 'lux'::text THEN c.lux
                                WHEN 'dli_today'::text THEN c.dli_today
                                WHEN 'dew_point'::text THEN c.dew_point
                                WHEN 'abs_humidity'::text THEN c.abs_humidity
                                WHEN 'enthalpy_delta'::text THEN c.enthalpy_delta
                                WHEN 'flow_gpm'::text THEN c.flow_gpm
                                WHEN 'water_total_gal'::text THEN c.water_total_gal
                                WHEN 'mister_water_today'::text THEN c.mister_water_today
                                WHEN 'outdoor_temp_f'::text THEN c.outdoor_temp_f
                                WHEN 'outdoor_rh_pct'::text THEN c.outdoor_rh_pct
                                WHEN 'wind_speed_mph'::text THEN c.wind_speed_mph
                                WHEN 'outdoor_lux'::text THEN c.outdoor_lux
                                WHEN 'solar_irradiance_w_m2'::text THEN c.solar_irradiance_w_m2
                                WHEN 'pressure_hpa'::text THEN c.pressure_hpa
                                WHEN 'uv_index'::text THEN c.uv_index
                                WHEN 'precip_in'::text THEN c.precip_in
                                WHEN 'feels_like_f'::text THEN c.feels_like_f
                                WHEN 'wet_bulb_temp_f'::text THEN c.wet_bulb_temp_f
                                WHEN 'hydro_ec_us_cm'::text THEN c.hydro_ec_us_cm
                                WHEN 'hydro_ph'::text THEN c.hydro_ph
                                WHEN 'hydro_tds_ppm'::text THEN c.hydro_tds_ppm
                                WHEN 'hydro_water_temp_f'::text THEN c.hydro_water_temp_f
                                WHEN 'hydro_orp_mv'::text THEN c.hydro_orp_mv
                                WHEN 'hydro_battery_pct'::text THEN c.hydro_battery_pct
                                ELSE NULL::double precision
                            END IS NOT NULL)))
                    WHEN 'equipment_state'::text THEN ( SELECT max(es.ts) AS max
                       FROM public.equipment_state es
                      WHERE (es.equipment = sr.source_column))
                    WHEN 'system_state'::text THEN ( SELECT max(ss.ts) AS max
                       FROM public.system_state ss
                      WHERE (ss.entity = sr.source_column))
                    WHEN 'diagnostics'::text THEN ( SELECT max(d.ts) AS max
                       FROM public.diagnostics d
                      WHERE (d.ts > (now() - '02:00:00'::interval)))
                    ELSE NULL::timestamp with time zone
                END AS last_seen_at
           FROM public.sensor_registry sr
          WHERE (sr.active = true)
        )
 SELECT sensor_id,
    type,
    zone,
    expected_interval_s,
    last_seen_at,
    (EXTRACT(epoch FROM (now() - last_seen_at)))::integer AS seconds_since,
        CASE
            WHEN (last_seen_at IS NULL) THEN true
            WHEN (EXTRACT(epoch FROM (now() - last_seen_at)) > ((expected_interval_s * 2))::numeric) THEN true
            ELSE false
        END AS is_stale,
        CASE
            WHEN (last_seen_at IS NULL) THEN NULL::numeric
            ELSE round((EXTRACT(epoch FROM (now() - last_seen_at)) / (NULLIF(expected_interval_s, 0))::numeric), 1)
        END AS staleness_ratio
   FROM last_readings;


ALTER VIEW public.v_sensor_staleness OWNER TO verdify;

--
-- Name: v_system_health_score; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_system_health_score AS
 SELECT 'sensor_health'::text AS component,
    round(((100.0 * (count(*) FILTER (WHERE (NOT v_sensor_staleness.is_stale)))::numeric) / (NULLIF(count(*), 0))::numeric), 1) AS score_pct,
    jsonb_build_object('total_sensors', count(*), 'healthy', count(*) FILTER (WHERE (NOT v_sensor_staleness.is_stale)), 'stale', count(*) FILTER (WHERE v_sensor_staleness.is_stale)) AS details,
    now() AS checked_at
   FROM public.v_sensor_staleness
UNION ALL
 SELECT 'alert_load'::text AS component,
    GREATEST((0)::numeric, round((100.0 - (COALESCE(sum(
        CASE alert_log.severity
            WHEN 'critical'::text THEN 10
            WHEN 'warning'::text THEN 3
            WHEN 'info'::text THEN 1
            ELSE 0
        END), (0)::bigint))::numeric), 1)) AS score_pct,
    jsonb_build_object('open_total', count(*), 'critical', count(*) FILTER (WHERE (alert_log.severity = 'critical'::text)), 'warning', count(*) FILTER (WHERE (alert_log.severity = 'warning'::text))) AS details,
    now() AS checked_at
   FROM public.alert_log
  WHERE (alert_log.disposition = 'open'::text)
UNION ALL
 SELECT 'equipment_health'::text AS component,
    (public.fn_equipment_health())::numeric AS score_pct,
    jsonb_build_object('score', public.fn_equipment_health()) AS details,
    now() AS checked_at
UNION ALL
 SELECT 'controller'::text AS component,
    round((
        CASE
            WHEN (d.ts IS NULL) THEN (0)::double precision
            ELSE LEAST((100)::double precision, (((GREATEST((0)::numeric, ((40)::numeric - (EXTRACT(epoch FROM (now() - d.ts)) / 15.0))))::double precision + LEAST((30)::double precision, GREATEST((0)::double precision, ((d.wifi_rssi + (80)::double precision) * (1.0)::double precision)))) + LEAST((30)::double precision, (d.uptime_s / (120.0)::double precision))))
        END)::numeric, 1) AS score_pct,
    jsonb_build_object('wifi_rssi_dbm', d.wifi_rssi, 'uptime_s', d.uptime_s, 'heap_bytes', d.heap_bytes) AS details,
    now() AS checked_at
   FROM ( SELECT diagnostics.ts,
            diagnostics.wifi_rssi,
            diagnostics.uptime_s,
            diagnostics.heap_bytes
           FROM public.diagnostics
          WHERE (diagnostics.ts > (now() - '00:10:00'::interval))
          ORDER BY diagnostics.ts DESC
         LIMIT 1) d;


ALTER VIEW public.v_system_health_score OWNER TO verdify;

--
-- Name: v_iris_planning_context; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_iris_planning_context AS
 SELECT now() AS query_ts,
    ( SELECT json_build_object('temp_avg', round((avg(climate.temp_avg))::numeric, 1), 'vpd_avg', round((avg(climate.vpd_avg))::numeric, 2), 'rh_avg', round((avg(climate.rh_avg))::numeric, 1), 'outdoor_temp_f', round((avg(climate.outdoor_temp_f))::numeric, 1), 'dli_today', round((max(climate.dli_today))::numeric, 2), 'co2_ppm', round((avg(climate.co2_ppm))::numeric, 0)) AS json_build_object
           FROM public.climate
          WHERE ((climate.ts >= (now() - '01:00:00'::interval)) AND (climate.temp_avg IS NOT NULL))) AS current_conditions,
    ( SELECT json_build_object('north', round((avg(climate.temp_north))::numeric, 1), 'south', round((avg(climate.temp_south))::numeric, 1), 'east', round((avg(climate.temp_east))::numeric, 1), 'west', round((avg(climate.temp_west))::numeric, 1)) AS json_build_object
           FROM public.climate
          WHERE ((climate.ts >= (now() - '01:00:00'::interval)) AND (climate.temp_avg IS NOT NULL))) AS zone_context,
    ( SELECT json_build_object('date', daily_summary.date, 'cost_total', daily_summary.cost_total, 'dli_final', daily_summary.dli_final, 'stress_hours_vpd_high', daily_summary.stress_hours_vpd_high, 'water_used_gal', daily_summary.water_used_gal) AS json_build_object
           FROM public.daily_summary
          ORDER BY daily_summary.date DESC
         LIMIT 1) AS yesterday_summary,
    ( SELECT json_build_object('predicted_dli', fn_forecast_dli.predicted_dli, 'gl_hours_needed', fn_forecast_dli.gl_hours_needed) AS json_build_object
           FROM public.fn_forecast_dli((CURRENT_DATE + 1)) fn_forecast_dli(predicted_dli, gl_hours_needed, recommended_gl_start, recommended_gl_end)) AS dli_forecast,
    ( SELECT json_object_agg(sub.parameter, sub.value) AS json_object_agg
           FROM ( SELECT DISTINCT ON (setpoint_changes.parameter) setpoint_changes.parameter,
                    setpoint_changes.value
                   FROM public.setpoint_changes
                  ORDER BY setpoint_changes.parameter, setpoint_changes.ts DESC) sub) AS current_setpoints,
    ( SELECT json_agg(row_to_json(sub.*) ORDER BY sub.ts) AS json_agg
           FROM ( SELECT setpoint_plan.ts,
                    setpoint_plan.parameter,
                    setpoint_plan.value,
                    setpoint_plan.reason
                   FROM public.setpoint_plan
                  WHERE ((setpoint_plan.ts > now()) AND (setpoint_plan.parameter <> 'plan_metadata'::text))
                  ORDER BY setpoint_plan.ts) sub) AS active_plan,
    ( SELECT json_build_object('composite_score', public.fn_system_health(), 'components', ( SELECT json_agg(json_build_object('component', v_system_health_score.component, 'score', v_system_health_score.score_pct)) AS json_agg
                   FROM public.v_system_health_score)) AS json_build_object) AS system_health,
    ( SELECT json_build_object('electric_per_kwh', 0.111, 'gas_per_therm', 1.20, 'water_per_gal', 0.00484) AS json_build_object) AS cost_rates;


ALTER VIEW public.v_iris_planning_context OWNER TO verdify;

