--
-- Name: v_light_transmission; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_light_transmission AS
 WITH indoor AS (
         SELECT public.time_bucket('00:05:00'::interval, climate.ts) AS bucket,
            avg(climate.lux) AS lux
           FROM public.climate
          WHERE (climate.lux IS NOT NULL)
          GROUP BY (public.time_bucket('00:05:00'::interval, climate.ts))
        ), outdoor AS (
         SELECT public.time_bucket('00:05:00'::interval, climate.ts) AS bucket,
            avg(climate.outdoor_lux) AS ppfd
           FROM public.climate
          WHERE ((climate.outdoor_lux IS NOT NULL) AND (climate.outdoor_lux > (0)::double precision))
          GROUP BY (public.time_bucket('00:05:00'::interval, climate.ts))
        )
 SELECT indoor.bucket AS ts,
    round((((indoor.lux / outdoor.ppfd) * (100)::double precision))::numeric, 1) AS transmission_pct
   FROM (indoor
     JOIN outdoor ON ((indoor.bucket = outdoor.bucket)));


ALTER VIEW public.v_light_transmission OWNER TO verdify;

--
-- Name: v_mister_effectiveness; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_mister_effectiveness AS
 WITH mister_events AS (
         SELECT equipment_state.ts,
            equipment_state.equipment,
            equipment_state.state,
            lead(equipment_state.ts) OVER (PARTITION BY equipment_state.equipment ORDER BY equipment_state.ts) AS next_ts,
            lead(equipment_state.state) OVER (PARTITION BY equipment_state.equipment ORDER BY equipment_state.ts) AS next_state
           FROM public.equipment_state
          WHERE ((equipment_state.equipment = ANY (ARRAY['mister_south'::text, 'mister_west'::text, 'mister_center'::text])) AND (equipment_state.ts > (now() - '14 days'::interval)))
        ), mister_cycles AS (
         SELECT mister_events.ts AS on_ts,
            mister_events.equipment,
            mister_events.next_ts AS off_ts,
            (EXTRACT(epoch FROM (mister_events.next_ts - mister_events.ts)))::integer AS duration_s
           FROM mister_events
          WHERE ((mister_events.state = true) AND (mister_events.next_state = false) AND ((mister_events.next_ts - mister_events.ts) < '00:30:00'::interval) AND ((mister_events.next_ts - mister_events.ts) > '00:00:05'::interval))
        )
 SELECT mc.on_ts,
    mc.equipment,
    mc.duration_s,
    round((vpd_before.vpd)::numeric, 2) AS vpd_before,
    round((vpd_after.vpd)::numeric, 2) AS vpd_after,
    round(((vpd_before.vpd - vpd_after.vpd))::numeric, 2) AS vpd_delta,
    round((outdoor.outdoor_temp)::numeric, 1) AS outdoor_temp_f,
    round((outdoor.outdoor_rh)::numeric, 0) AS outdoor_rh_pct
   FROM (((mister_cycles mc
     LEFT JOIN LATERAL ( SELECT climate.vpd_avg AS vpd
           FROM public.climate
          WHERE ((climate.ts <= mc.on_ts) AND (climate.vpd_avg IS NOT NULL))
          ORDER BY climate.ts DESC
         LIMIT 1) vpd_before ON (true))
     LEFT JOIN LATERAL ( SELECT climate.vpd_avg AS vpd
           FROM public.climate
          WHERE ((climate.ts >= mc.off_ts) AND (climate.vpd_avg IS NOT NULL))
          ORDER BY climate.ts
         LIMIT 1) vpd_after ON (true))
     LEFT JOIN LATERAL ( SELECT climate.outdoor_temp_f AS outdoor_temp,
            climate.outdoor_rh_pct AS outdoor_rh
           FROM public.climate
          WHERE ((climate.ts <= mc.on_ts) AND (climate.outdoor_temp_f IS NOT NULL))
          ORDER BY climate.ts DESC
         LIMIT 1) outdoor ON (true))
  ORDER BY mc.on_ts DESC;


ALTER VIEW public.v_mister_effectiveness OWNER TO verdify;

--
-- Name: VIEW v_mister_effectiveness; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_mister_effectiveness IS 'VPD before/after each misting cycle with outdoor context. vpd_delta > 0 = improvement.';


--
-- Name: v_monthly_summary; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_monthly_summary AS
 SELECT (date_trunc('month'::text, (date)::timestamp with time zone))::date AS month_start,
    count(*) AS days,
    round((avg(temp_avg))::numeric, 1) AS temp_avg,
    round((min(temp_min))::numeric, 1) AS temp_min,
    round((max(temp_max))::numeric, 1) AS temp_max,
    round((avg(rh_avg))::numeric, 1) AS rh_avg,
    round((min(rh_min))::numeric, 1) AS rh_min,
    round((max(rh_max))::numeric, 1) AS rh_max,
    round((avg(vpd_avg))::numeric, 2) AS vpd_avg,
    round((min(vpd_min))::numeric, 2) AS vpd_min,
    round((max(vpd_max))::numeric, 2) AS vpd_max,
    round((avg(dli_final))::numeric, 1) AS dli_avg,
    round((avg(co2_avg))::numeric, 0) AS co2_avg,
    round((min(outdoor_temp_min))::numeric, 1) AS outdoor_temp_min,
    round((max(outdoor_temp_max))::numeric, 1) AS outdoor_temp_max,
    round((sum(COALESCE(stress_hours_heat, (0)::double precision)))::numeric, 1) AS stress_hours_heat,
    round((sum(COALESCE(stress_hours_cold, (0)::double precision)))::numeric, 1) AS stress_hours_cold,
    round((sum(COALESCE(stress_hours_vpd_high, (0)::double precision)))::numeric, 1) AS stress_hours_vpd_high,
    round((sum(COALESCE(stress_hours_vpd_low, (0)::double precision)))::numeric, 1) AS stress_hours_vpd_low,
    round((sum(COALESCE(water_used_gal, (0)::double precision)))::numeric, 0) AS total_water_gal,
    round((sum(COALESCE(mister_water_gal, (0)::double precision)))::numeric, 0) AS mister_water_gal,
    round((sum(COALESCE(kwh_estimated, (0)::double precision)))::numeric, 1) AS kwh_total,
    round((sum(COALESCE(therms_estimated, (0)::double precision)))::numeric, 2) AS therms_total,
    round((sum(COALESCE(cost_electric, (0)::double precision)))::numeric, 2) AS cost_electric,
    round((sum(COALESCE(cost_gas, (0)::double precision)))::numeric, 2) AS cost_gas,
    round((sum(COALESCE(cost_water, (0)::double precision)))::numeric, 2) AS cost_water,
    round((sum(COALESCE(cost_total, (0)::double precision)))::numeric, 2) AS total_cost,
    round(((sum(COALESCE(runtime_heat1_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_heat1_h,
    round(((sum(COALESCE(runtime_heat2_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_heat2_h,
    round(((sum(COALESCE((runtime_fan1_min + runtime_fan2_min), (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_fans_h,
    round(((sum(COALESCE(runtime_fog_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_fog_h,
    round(((sum(COALESCE(runtime_vent_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_vent_h,
    round(((sum(COALESCE(runtime_grow_light_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_grow_light_h,
    round((sum(COALESCE(((runtime_mister_south_h + runtime_mister_west_h) + runtime_mister_center_h), (0)::double precision)))::numeric, 1) AS runtime_misters_h,
    sum((COALESCE(cycles_heat1, 0) + COALESCE(cycles_heat2, 0))) AS cycles_heat,
    sum((COALESCE(cycles_fan1, 0) + COALESCE(cycles_fan2, 0))) AS cycles_fans,
    sum(COALESCE(cycles_fog, 0)) AS cycles_fog,
    sum(COALESCE(cycles_vent, 0)) AS cycles_vent
   FROM public.daily_summary
  WHERE (temp_avg IS NOT NULL)
  GROUP BY (date_trunc('month'::text, (date)::timestamp with time zone))
  ORDER BY ((date_trunc('month'::text, (date)::timestamp with time zone))::date);


ALTER VIEW public.v_monthly_summary OWNER TO verdify;

--
-- Name: VIEW v_monthly_summary; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_monthly_summary IS 'Calendar month aggregation of daily_summary.';


