--
-- Name: v_plan_compliance; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_plan_compliance AS
 WITH plan_params AS (
         SELECT setpoint_plan.ts AS planned_ts,
            setpoint_plan.parameter,
            setpoint_plan.value AS planned_value,
            setpoint_plan.plan_id,
            setpoint_plan.reason,
                CASE setpoint_plan.parameter
                    WHEN 'temp_high'::text THEN 'temp_ceiling'::text
                    WHEN 'temp_low'::text THEN 'temp_floor'::text
                    WHEN 'vpd_high'::text THEN 'vpd_ceiling'::text
                    WHEN 'vpd_low'::text THEN 'vpd_floor'::text
                    ELSE NULL::text
                END AS target_type
           FROM public.setpoint_plan
          WHERE ((setpoint_plan.parameter = ANY (ARRAY['temp_low'::text, 'temp_high'::text, 'vpd_low'::text, 'vpd_high'::text])) AND (setpoint_plan.ts < now()))
        ), hourly_climate AS (
         SELECT public.time_bucket('01:00:00'::interval, climate.ts) AS hour,
            max(climate.temp_avg) AS max_temp,
            min(climate.temp_avg) AS min_temp,
            max(climate.vpd_avg) AS max_vpd,
            min(climate.vpd_avg) AS min_vpd
           FROM public.climate
          WHERE ((climate.temp_avg IS NOT NULL) AND (climate.ts > (now() - '7 days'::interval)))
          GROUP BY (public.time_bucket('01:00:00'::interval, climate.ts))
        )
 SELECT pp.planned_ts,
    pp.parameter,
    pp.planned_value,
    pp.target_type,
    round((
        CASE pp.target_type
            WHEN 'temp_ceiling'::text THEN hc.max_temp
            WHEN 'temp_floor'::text THEN hc.min_temp
            WHEN 'vpd_ceiling'::text THEN hc.max_vpd
            WHEN 'vpd_floor'::text THEN hc.min_vpd
            ELSE NULL::double precision
        END)::numeric, 1) AS actual_extreme,
        CASE pp.target_type
            WHEN 'temp_ceiling'::text THEN (hc.max_temp <= pp.planned_value)
            WHEN 'temp_floor'::text THEN (hc.min_temp >= pp.planned_value)
            WHEN 'vpd_ceiling'::text THEN (hc.max_vpd <= pp.planned_value)
            WHEN 'vpd_floor'::text THEN (hc.min_vpd >= pp.planned_value)
            ELSE NULL::boolean
        END AS plan_achieved,
    round(((
        CASE pp.target_type
            WHEN 'temp_ceiling'::text THEN hc.max_temp
            WHEN 'temp_floor'::text THEN hc.min_temp
            WHEN 'vpd_ceiling'::text THEN hc.max_vpd
            WHEN 'vpd_floor'::text THEN hc.min_vpd
            ELSE NULL::double precision
        END - pp.planned_value))::numeric, 2) AS overshoot,
    pp.plan_id,
    pp.reason
   FROM (plan_params pp
     JOIN hourly_climate hc ON ((hc.hour = public.time_bucket('01:00:00'::interval, pp.planned_ts))))
  WHERE (pp.target_type IS NOT NULL);


ALTER VIEW public.v_plan_compliance OWNER TO verdify;

--
-- Name: VIEW v_plan_compliance; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_plan_compliance IS 'Plan waypoints vs actual climate via hourly bucketed JOIN (fast). Scans last 7 days.';


--
-- Name: v_plan_accuracy; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_plan_accuracy AS
 SELECT plan_id,
    count(*) AS waypoints,
    count(*) FILTER (WHERE plan_achieved) AS achieved,
    round(((100.0 * (count(*) FILTER (WHERE plan_achieved))::numeric) / (NULLIF(count(*), 0))::numeric), 1) AS accuracy_pct,
    round(avg(abs(overshoot)), 2) AS mean_abs_error,
    max(overshoot) FILTER (WHERE (target_type ~~ '%ceiling'::text)) AS worst_ceiling_overshoot,
    min(overshoot) FILTER (WHERE (target_type ~~ '%floor'::text)) AS worst_floor_undershoot,
    min(planned_ts) AS plan_start,
    max(planned_ts) AS plan_end
   FROM public.v_plan_compliance
  GROUP BY plan_id;


ALTER VIEW public.v_plan_accuracy OWNER TO verdify;

--
-- Name: VIEW v_plan_accuracy; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_plan_accuracy IS 'Per-plan accuracy summary.';


--
-- Name: v_plan_accuracy_72h; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_plan_accuracy_72h AS
 WITH plan_starts AS (
         SELECT v_plan_compliance.plan_id,
            min(v_plan_compliance.planned_ts) AS plan_start
           FROM public.v_plan_compliance
          GROUP BY v_plan_compliance.plan_id
        )
 SELECT c.plan_id,
    (((EXTRACT(epoch FROM (c.planned_ts - ps.plan_start)) / (86400)::numeric))::integer + 1) AS day_offset,
    count(*) AS waypoints_count,
    count(*) FILTER (WHERE c.plan_achieved) AS achieved_count,
    round(((100.0 * (count(*) FILTER (WHERE c.plan_achieved))::numeric) / (NULLIF(count(*), 0))::numeric), 1) AS accuracy_pct,
    round(avg(abs(c.overshoot)), 2) AS mean_abs_error
   FROM (public.v_plan_compliance c
     JOIN plan_starts ps USING (plan_id))
  WHERE (((EXTRACT(epoch FROM (c.planned_ts - ps.plan_start)) / (86400)::numeric))::integer < 3)
  GROUP BY c.plan_id, (((EXTRACT(epoch FROM (c.planned_ts - ps.plan_start)) / (86400)::numeric))::integer + 1)
  ORDER BY c.plan_id, (((EXTRACT(epoch FROM (c.planned_ts - ps.plan_start)) / (86400)::numeric))::integer + 1);


ALTER VIEW public.v_plan_accuracy_72h OWNER TO verdify;

--
-- Name: VIEW v_plan_accuracy_72h; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_plan_accuracy_72h IS 'Per-day accuracy within 72h plans. day_offset: 1=first 24h, 2=24-48h, 3=48-72h.';


--
-- Name: v_plan_accuracy_by_day; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_plan_accuracy_by_day AS
 SELECT plan_id,
    ((planned_ts AT TIME ZONE 'America/Denver'::text))::date AS day,
    count(*) AS waypoints,
    count(*) FILTER (WHERE plan_achieved) AS achieved,
    round(((100.0 * (count(*) FILTER (WHERE plan_achieved))::numeric) / (NULLIF(count(*), 0))::numeric), 1) AS accuracy_pct,
    round(avg(abs(overshoot)), 2) AS mean_abs_error
   FROM public.v_plan_compliance
  GROUP BY plan_id, (((planned_ts AT TIME ZONE 'America/Denver'::text))::date);


ALTER VIEW public.v_plan_accuracy_by_day OWNER TO verdify;

--
-- Name: v_plan_comparison; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_plan_comparison AS
 WITH plan_order AS (
         SELECT DISTINCT setpoint_plan.plan_id,
            min(setpoint_plan.created_at) AS created_at
           FROM public.setpoint_plan
          WHERE ((setpoint_plan.plan_id ~~ 'iris-2026%'::text) AND (setpoint_plan.plan_id !~~ '%reactive%'::text) AND (setpoint_plan.plan_id !~~ '%fix%'::text) AND (setpoint_plan.plan_id !~~ '%dev%'::text))
          GROUP BY setpoint_plan.plan_id
          ORDER BY (min(setpoint_plan.created_at)) DESC
         LIMIT 20
        ), plan_pairs AS (
         SELECT plan_order.plan_id,
            plan_order.created_at,
            lag(plan_order.plan_id) OVER (ORDER BY plan_order.created_at) AS prev_plan_id
           FROM plan_order
        ), cur_stats AS (
         SELECT sp.plan_id,
            sp.parameter,
            count(*) AS waypoints,
            round((avg(sp.value))::numeric, 2) AS avg_value,
            round((min(sp.value))::numeric, 2) AS min_value,
            round((max(sp.value))::numeric, 2) AS max_value
           FROM (public.setpoint_plan sp
             JOIN plan_pairs pp_1 ON ((sp.plan_id = pp_1.plan_id)))
          WHERE (sp.parameter = ANY (ARRAY['temp_high'::text, 'temp_low'::text, 'vpd_high'::text, 'vpd_hysteresis'::text, 'd_cool_stage_2'::text, 'mister_engage_kpa'::text, 'mister_all_kpa'::text, 'mister_pulse_on_s'::text, 'mister_pulse_gap_s'::text, 'mister_vpd_weight'::text]))
          GROUP BY sp.plan_id, sp.parameter
        ), prev_stats AS (
         SELECT sp.plan_id AS prev_plan_id,
            sp.parameter,
            count(*) AS waypoints,
            round((avg(sp.value))::numeric, 2) AS avg_value,
            round((min(sp.value))::numeric, 2) AS min_value,
            round((max(sp.value))::numeric, 2) AS max_value
           FROM (public.setpoint_plan sp
             JOIN plan_pairs pp_1 ON ((sp.plan_id = pp_1.prev_plan_id)))
          WHERE (sp.parameter = ANY (ARRAY['temp_high'::text, 'temp_low'::text, 'vpd_high'::text, 'vpd_hysteresis'::text, 'd_cool_stage_2'::text, 'mister_engage_kpa'::text, 'mister_all_kpa'::text, 'mister_pulse_on_s'::text, 'mister_pulse_gap_s'::text, 'mister_vpd_weight'::text]))
          GROUP BY sp.plan_id, sp.parameter
        )
 SELECT pp.plan_id,
    pp.prev_plan_id,
    (pp.created_at AT TIME ZONE 'America/Denver'::text) AS plan_created,
    COALESCE(c.parameter, p.parameter) AS parameter,
    COALESCE(c.waypoints, (0)::bigint) AS cur_waypoints,
    COALESCE(p.waypoints, (0)::bigint) AS prev_waypoints,
    c.avg_value AS cur_avg,
    p.avg_value AS prev_avg,
    round((COALESCE(c.avg_value, (0)::numeric) - COALESCE(p.avg_value, (0)::numeric)), 2) AS delta_avg,
    c.min_value AS cur_min,
    c.max_value AS cur_max,
    p.min_value AS prev_min,
    p.max_value AS prev_max
   FROM ((plan_pairs pp
     LEFT JOIN cur_stats c ON ((pp.plan_id = c.plan_id)))
     LEFT JOIN prev_stats p ON (((pp.prev_plan_id = p.prev_plan_id) AND (COALESCE(c.parameter, p.parameter) = p.parameter))))
  WHERE ((pp.prev_plan_id IS NOT NULL) AND ((c.parameter IS NOT NULL) OR (p.parameter IS NOT NULL)))
  ORDER BY pp.created_at DESC, COALESCE(c.parameter, p.parameter);


ALTER VIEW public.v_plan_comparison OWNER TO verdify;

--
-- Name: v_planner_performance; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_planner_performance AS
 WITH daily AS (
         SELECT daily_summary.date,
            COALESCE(daily_summary.stress_hours_heat, (0)::double precision) AS heat_stress_h,
            COALESCE(daily_summary.stress_hours_cold, (0)::double precision) AS cold_stress_h,
            COALESCE(daily_summary.stress_hours_vpd_high, (0)::double precision) AS vpd_high_stress_h,
            COALESCE(daily_summary.stress_hours_vpd_low, (0)::double precision) AS vpd_low_stress_h,
            (((COALESCE(daily_summary.stress_hours_heat, (0)::double precision) + COALESCE(daily_summary.stress_hours_cold, (0)::double precision)) + COALESCE(daily_summary.stress_hours_vpd_high, (0)::double precision)) + COALESCE(daily_summary.stress_hours_vpd_low, (0)::double precision)) AS total_stress_h,
            COALESCE(daily_summary.cost_total, (0)::double precision) AS cost_total,
            COALESCE(daily_summary.cost_electric, (0)::double precision) AS cost_electric,
            COALESCE(daily_summary.cost_gas, (0)::double precision) AS cost_gas,
            COALESCE(daily_summary.cost_water, (0)::double precision) AS cost_water
           FROM public.daily_summary
          WHERE (daily_summary.date IS NOT NULL)
        )
 SELECT date,
    heat_stress_h,
    cold_stress_h,
    vpd_high_stress_h,
    vpd_low_stress_h,
    total_stress_h,
    round(((((1.0)::double precision - LEAST((total_stress_h / (24.0)::double precision), (1.0)::double precision)) * (100)::double precision))::numeric, 1) AS compliance_pct,
    cost_total,
    cost_electric,
    cost_gas,
    cost_water,
        CASE
            WHEN (total_stress_h > (0)::double precision) THEN round(((cost_total / total_stress_h))::numeric, 2)
            ELSE NULL::numeric
        END AS cost_per_stress_hour,
    round((((((1.0)::double precision - LEAST((total_stress_h / (24.0)::double precision), (1.0)::double precision)) * (80)::double precision) + (GREATEST((0)::double precision, ((1.0)::double precision - LEAST((cost_total / (15.0)::double precision), (1.0)::double precision))) * (20)::double precision)))::numeric, 1) AS planner_score
   FROM daily;


ALTER VIEW public.v_planner_performance OWNER TO verdify;

--
-- Name: VIEW v_planner_performance; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_planner_performance IS 'Top-level KPI: planner_score (0-100). Priority 1: compliance/in-band time (80%). Priority 2: cost efficiency (20%). Used by planner self-assessment.';


--
-- Name: v_reboot_log; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_reboot_log AS
 SELECT ts,
    uptime_s AS uptime_after,
    reset_reason,
    lag(uptime_s) OVER (ORDER BY ts) AS uptime_before,
    (EXTRACT(epoch FROM (ts - lag(ts) OVER (ORDER BY ts))))::integer AS gap_s
   FROM public.diagnostics
  WHERE ((uptime_s < (300)::double precision) AND (ts > (now() - '90 days'::interval)))
  ORDER BY ts DESC;


ALTER VIEW public.v_reboot_log OWNER TO verdify;

--
-- Name: v_relay_stuck; Type: MATERIALIZED VIEW; Schema: public; Owner: verdify
--

CREATE MATERIALIZED VIEW public.v_relay_stuck AS
 WITH latest_on AS (
         SELECT equipment_state.equipment,
            max(equipment_state.ts) AS last_on_ts
           FROM public.equipment_state
          WHERE ((equipment_state.state = true) AND (equipment_state.equipment <> ALL (ARRAY['economiser_enabled'::text, 'economiser_blocked'::text, 'fog_closes_vent'::text, 'irrigation_enabled'::text, 'irrigation_wall_enabled'::text, 'irrigation_center_enabled'::text, 'irrigation_weather_skip'::text, 'sntp_status'::text, 'mister_budget_exceeded'::text, 'fan_burst_active'::text, 'fog_burst_active'::text, 'vent_bypass_active'::text, 'leak_detected'::text, 'water_flowing'::text, 'mister_any'::text, 'gl_auto_mode'::text, 'occupancy_inhibit'::text])))
          GROUP BY equipment_state.equipment
        ), latest_off AS (
         SELECT equipment_state.equipment,
            max(equipment_state.ts) AS last_off_ts
           FROM public.equipment_state
          WHERE (equipment_state.state = false)
          GROUP BY equipment_state.equipment
        ), stuck_check AS (
         SELECT lo.equipment,
            lo.last_on_ts,
            lf.last_off_ts,
            (EXTRACT(epoch FROM (now() - lo.last_on_ts)) / 3600.0) AS hours_on,
                CASE lo.equipment
                    WHEN 'heat1'::text THEN 3
                    WHEN 'heat2'::text THEN 3
                    WHEN 'fan1'::text THEN 4
                    WHEN 'fan2'::text THEN 4
                    WHEN 'fog'::text THEN 2
                    WHEN 'vent'::text THEN 6
                    ELSE 8
                END AS threshold_hours
           FROM (latest_on lo
             LEFT JOIN latest_off lf ON ((lo.equipment = lf.equipment)))
          WHERE (lo.last_on_ts > COALESCE(lf.last_off_ts, '1970-01-01 00:00:00+00'::timestamp with time zone))
        )
 SELECT equipment,
    last_on_ts,
    hours_on,
    threshold_hours,
    (hours_on > (threshold_hours)::numeric) AS is_stuck
   FROM stuck_check
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.v_relay_stuck OWNER TO verdify;

--
-- Name: v_setpoint_compliance; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_setpoint_compliance AS
 WITH zone_readings AS (
         SELECT climate.ts,
            'south'::text AS zone,
            climate.temp_south AS actual_temp,
            climate.rh_south AS actual_rh,
            climate.vpd_south AS actual_vpd
           FROM public.climate
          WHERE (climate.temp_south IS NOT NULL)
        UNION ALL
         SELECT climate.ts,
            'north'::text,
            climate.temp_north,
            climate.rh_north,
            climate.vpd_north
           FROM public.climate
          WHERE (climate.temp_north IS NOT NULL)
        UNION ALL
         SELECT climate.ts,
            'east'::text,
            climate.temp_east,
            climate.rh_east,
            climate.vpd_east
           FROM public.climate
          WHERE (climate.temp_east IS NOT NULL)
        UNION ALL
         SELECT climate.ts,
            'west'::text,
            climate.temp_west,
            climate.rh_west,
            climate.vpd_west
           FROM public.climate
          WHERE (climate.temp_west IS NOT NULL)
        UNION ALL
         SELECT climate.ts,
            'greenhouse'::text AS zone,
            climate.temp_avg,
            climate.rh_avg,
            climate.vpd_avg
           FROM public.climate
          WHERE (climate.temp_avg IS NOT NULL)
        )
 SELECT zr.ts,
    zr.zone,
    round((zr.actual_temp)::numeric, 1) AS actual_temp,
    (ss.temp_target_f)::numeric AS target_temp,
    ((zr.actual_temp >= ((ss.temp_target_f - 2.0))::double precision) AND (zr.actual_temp <= ((ss.temp_target_f + 2.0))::double precision)) AS temp_in_range,
    round((zr.actual_rh)::numeric, 1) AS actual_rh,
    (ss.humidity_target_pct)::numeric AS target_rh,
    ((zr.actual_rh >= ((ss.humidity_target_pct - 5.0))::double precision) AND (zr.actual_rh <= ((ss.humidity_target_pct + 5.0))::double precision)) AS rh_in_range,
    round((zr.actual_vpd)::numeric, 2) AS actual_vpd,
    (ss.vpd_target_kpa)::numeric AS target_vpd,
    ((zr.actual_vpd >= ((ss.vpd_target_kpa - 0.15))::double precision) AND (zr.actual_vpd <= ((ss.vpd_target_kpa + 0.15))::double precision)) AS vpd_in_range,
    (((zr.actual_temp >= ((ss.temp_target_f - 2.0))::double precision) AND (zr.actual_temp <= ((ss.temp_target_f + 2.0))::double precision)) AND ((zr.actual_rh >= ((ss.humidity_target_pct - 5.0))::double precision) AND (zr.actual_rh <= ((ss.humidity_target_pct + 5.0))::double precision)) AND ((zr.actual_vpd >= ((ss.vpd_target_kpa - 0.15))::double precision) AND (zr.actual_vpd <= ((ss.vpd_target_kpa + 0.15))::double precision))) AS overall_compliant
   FROM (zone_readings zr
     JOIN public.setpoint_schedule ss ON (((ss.zone =
        CASE
            WHEN (zr.zone = 'greenhouse'::text) THEN 'south'::text
            ELSE zr.zone
        END) AND (ss.hour_of_day = (EXTRACT(hour FROM (zr.ts AT TIME ZONE 'America/Denver'::text)))::integer) AND (ss.season = public.fn_current_season()))));


ALTER VIEW public.v_setpoint_compliance OWNER TO verdify;

--
-- Name: VIEW v_setpoint_compliance; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_setpoint_compliance IS 'Climate readings vs setpoint_schedule targets. Tolerance: ±2°F temp, ±5% RH, ±0.15 kPa VPD. Greenhouse-wide uses south zone targets.';


--
-- Name: v_setpoint_forward; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_setpoint_forward AS
 SELECT v_active_plan.parameter,
    now() AS ts,
    v_active_plan.value,
    'current'::text AS source
   FROM public.v_active_plan
  WHERE (v_active_plan.parameter = ANY (ARRAY['temp_high'::text, 'temp_low'::text, 'vpd_high'::text, 'vpd_low'::text, 'vpd_hysteresis'::text, 'd_cool_stage_2'::text, 'mister_engage_kpa'::text, 'mister_all_kpa'::text, 'mister_pulse_on_s'::text, 'mister_pulse_gap_s'::text]))
UNION ALL
 SELECT v_active_plan.parameter,
    COALESCE(( SELECT max(weather_forecast.ts) AS max
           FROM public.weather_forecast
          WHERE (weather_forecast.fetched_at > (now() - '12:00:00'::interval))), (now() + '16 days'::interval)) AS ts,
    v_active_plan.value,
    'projection'::text AS source
   FROM public.v_active_plan
  WHERE (v_active_plan.parameter = ANY (ARRAY['temp_high'::text, 'temp_low'::text, 'vpd_high'::text, 'vpd_low'::text, 'vpd_hysteresis'::text, 'd_cool_stage_2'::text, 'mister_engage_kpa'::text, 'mister_all_kpa'::text, 'mister_pulse_on_s'::text, 'mister_pulse_gap_s'::text]))
UNION ALL
 SELECT setpoint_plan.parameter,
    setpoint_plan.ts,
    setpoint_plan.value,
    'plan'::text AS source
   FROM public.setpoint_plan
  WHERE ((setpoint_plan.parameter = ANY (ARRAY['temp_high'::text, 'temp_low'::text, 'vpd_high'::text, 'vpd_low'::text, 'vpd_hysteresis'::text, 'd_cool_stage_2'::text, 'mister_engage_kpa'::text, 'mister_all_kpa'::text, 'mister_pulse_on_s'::text, 'mister_pulse_gap_s'::text])) AND (setpoint_plan.is_active = true) AND (setpoint_plan.ts > now()))
  ORDER BY 1, 2;


ALTER VIEW public.v_setpoint_forward OWNER TO verdify;

--
-- Name: v_setpoint_velocity; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_setpoint_velocity AS
 WITH hourly AS (
         SELECT date_trunc('hour'::text, sc.ts) AS hour,
            sc.parameter,
            sc.source,
            count(*) AS writes,
            count(*) FILTER (WHERE (EXISTS ( SELECT 1
                   FROM public.setpoint_changes sc2
                  WHERE ((sc2.parameter = sc.parameter) AND (sc2.ts > sc.ts) AND (sc2.ts < (sc.ts + '00:10:00'::interval)) AND (sc2.value <> sc.value))))) AS oscillations
           FROM public.setpoint_changes sc
          WHERE (sc.ts > (now() - '30 days'::interval))
          GROUP BY (date_trunc('hour'::text, sc.ts)), sc.parameter, sc.source
        )
 SELECT hour,
    parameter,
    source,
    writes,
    oscillations
   FROM hourly;


ALTER VIEW public.v_setpoint_velocity OWNER TO verdify;

--
-- Name: v_soil_status; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_soil_status AS
 WITH latest AS (
         SELECT climate.ts,
            climate.soil_moisture_south_1,
            climate.soil_temp_south_1,
            climate.soil_ec_south_1,
            climate.soil_moisture_south_2,
            climate.soil_temp_south_2,
            climate.soil_moisture_west,
            climate.soil_temp_west
           FROM public.climate
          WHERE ((climate.soil_moisture_south_1 IS NOT NULL) OR (climate.soil_moisture_west IS NOT NULL))
          ORDER BY climate.ts DESC
         LIMIT 1
        ), trend AS (
         SELECT avg(recent.soil_moisture_south_1) AS avg_s1,
            avg(recent.soil_moisture_south_2) AS avg_s2,
            avg(recent.soil_moisture_west) AS avg_w,
            (array_agg(recent.soil_moisture_south_1 ORDER BY recent.ts DESC))[1] AS last_s1,
            (array_agg(recent.soil_moisture_south_1 ORDER BY recent.ts))[1] AS first_s1,
            (array_agg(recent.soil_moisture_south_2 ORDER BY recent.ts DESC))[1] AS last_s2,
            (array_agg(recent.soil_moisture_south_2 ORDER BY recent.ts))[1] AS first_s2,
            (array_agg(recent.soil_moisture_west ORDER BY recent.ts DESC))[1] AS last_w,
            (array_agg(recent.soil_moisture_west ORDER BY recent.ts))[1] AS first_w
           FROM ( SELECT climate.ts,
                    climate.soil_moisture_south_1,
                    climate.soil_moisture_south_2,
                    climate.soil_moisture_west
                   FROM public.climate
                  WHERE (((climate.soil_moisture_south_1 IS NOT NULL) OR (climate.soil_moisture_west IS NOT NULL)) AND (climate.ts > (now() - '06:00:00'::interval)))
                  ORDER BY climate.ts DESC
                 LIMIT 6) recent
        ), unpivoted AS (
         SELECT 'south_1'::text AS zone,
            l.soil_moisture_south_1 AS moisture,
            l.soil_temp_south_1 AS temp,
            l.soil_ec_south_1 AS ec,
            (EXTRACT(epoch FROM (now() - l.ts)))::integer AS age_s,
                CASE
                    WHEN ((t_1.last_s1 - t_1.first_s1) > (2)::double precision) THEN 'rising'::text
                    WHEN ((t_1.first_s1 - t_1.last_s1) > (2)::double precision) THEN 'falling'::text
                    ELSE 'stable'::text
                END AS trend
           FROM latest l,
            trend t_1
        UNION ALL
         SELECT 'south_2'::text,
            l.soil_moisture_south_2,
            l.soil_temp_south_2,
            NULL::double precision,
            (EXTRACT(epoch FROM (now() - l.ts)))::integer AS "extract",
                CASE
                    WHEN ((t_1.last_s2 - t_1.first_s2) > (2)::double precision) THEN 'rising'::text
                    WHEN ((t_1.first_s2 - t_1.last_s2) > (2)::double precision) THEN 'falling'::text
                    ELSE 'stable'::text
                END AS "case"
           FROM latest l,
            trend t_1
        UNION ALL
         SELECT 'west'::text,
            l.soil_moisture_west,
            l.soil_temp_west,
            NULL::double precision,
            (EXTRACT(epoch FROM (now() - l.ts)))::integer AS "extract",
                CASE
                    WHEN ((t_1.last_w - t_1.first_w) > (2)::double precision) THEN 'rising'::text
                    WHEN ((t_1.first_w - t_1.last_w) > (2)::double precision) THEN 'falling'::text
                    ELSE 'stable'::text
                END AS "case"
           FROM latest l,
            trend t_1
        )
 SELECT u.zone,
    u.moisture,
    u.temp,
    u.ec,
    u.age_s,
    u.trend,
    t.min_pct,
    t.max_pct,
    t.crop,
        CASE
            WHEN (u.moisture IS NULL) THEN 'offline'::text
            WHEN (u.moisture < (t.wilt_pct)::double precision) THEN 'critical_dry'::text
            WHEN (u.moisture < (t.min_pct)::double precision) THEN 'dry'::text
            WHEN (u.moisture > (t.saturation_pct)::double precision) THEN 'saturated'::text
            WHEN (u.moisture > (t.max_pct)::double precision) THEN 'wet'::text
            ELSE 'ok'::text
        END AS status
   FROM (unpivoted u
     LEFT JOIN public.soil_moisture_targets t ON ((u.zone = t.zone)));


ALTER VIEW public.v_soil_status OWNER TO verdify;

--
-- Name: v_state_durations; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_state_durations AS
 WITH transitions AS (
         SELECT system_state.ts,
            system_state.value AS state,
            lead(system_state.ts) OVER (ORDER BY system_state.ts) AS next_ts
           FROM public.system_state
          WHERE ((system_state.entity = 'greenhouse_state'::text) AND (system_state.ts > (now() - '30 days'::interval)))
        )
 SELECT (ts)::date AS date,
    state,
    round(sum((EXTRACT(epoch FROM (COALESCE(next_ts, now()) - ts)) / (3600)::numeric)), 2) AS hours,
    count(*) AS transitions
   FROM transitions
  GROUP BY ((ts)::date), state
  ORDER BY ((ts)::date) DESC, (round(sum((EXTRACT(epoch FROM (COALESCE(next_ts, now()) - ts)) / (3600)::numeric)), 2)) DESC;


ALTER VIEW public.v_state_durations OWNER TO verdify;

--
-- Name: VIEW v_state_durations; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_state_durations IS 'Hours spent in each state per day. Feeds plan accuracy: predicted vs actual time in COOL/HEAT/HUMID states.';


--
-- Name: v_state_transition_rate; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_state_transition_rate AS
 SELECT date_trunc('hour'::text, ts) AS hour,
    count(*) AS transitions,
    count(DISTINCT value) AS unique_states
   FROM public.system_state
  WHERE ((entity = 'greenhouse_state'::text) AND (ts > (now() - '30 days'::interval)))
  GROUP BY (date_trunc('hour'::text, ts));


ALTER VIEW public.v_state_transition_rate OWNER TO verdify;

--
-- Name: v_stress_hours_today; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_stress_hours_today AS
 WITH latest_setpoints AS (
         SELECT DISTINCT ON (setpoint_changes.parameter) setpoint_changes.parameter,
            setpoint_changes.value
           FROM public.setpoint_changes
          ORDER BY setpoint_changes.parameter, setpoint_changes.ts DESC
        )
 SELECT date_trunc('day'::text, ts) AS date,
    round(sum(
        CASE
            WHEN (temp_avg < ( SELECT latest_setpoints.value
               FROM latest_setpoints
              WHERE (latest_setpoints.parameter = 'temp_low'::text))) THEN (2.0 / 60.0)
            ELSE (0)::numeric
        END), 2) AS cold_stress_hours,
    round(sum(
        CASE
            WHEN (temp_avg > ( SELECT latest_setpoints.value
               FROM latest_setpoints
              WHERE (latest_setpoints.parameter = 'temp_high'::text))) THEN (2.0 / 60.0)
            ELSE (0)::numeric
        END), 2) AS heat_stress_hours,
    round(sum(
        CASE
            WHEN (vpd_avg > ( SELECT latest_setpoints.value
               FROM latest_setpoints
              WHERE (latest_setpoints.parameter = 'vpd_high'::text))) THEN (2.0 / 60.0)
            ELSE (0)::numeric
        END), 2) AS vpd_stress_hours,
    round(sum(
        CASE
            WHEN (vpd_avg < ( SELECT latest_setpoints.value
               FROM latest_setpoints
              WHERE (latest_setpoints.parameter = 'vpd_low'::text))) THEN (2.0 / 60.0)
            ELSE (0)::numeric
        END), 2) AS vpd_low_hours
   FROM public.climate
  WHERE ((temp_avg IS NOT NULL) AND (vpd_avg IS NOT NULL))
  GROUP BY (date_trunc('day'::text, ts))
  ORDER BY (date_trunc('day'::text, ts));


ALTER VIEW public.v_stress_hours_today OWNER TO verdify;

--
-- Name: v_succession_gaps; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_succession_gaps AS
 WITH current_crops AS (
         SELECT crops.id,
            crops.name,
            crops.zone,
            crops."position",
            crops.expected_harvest,
            crops.is_active
           FROM public.crops
          WHERE (crops.is_active = true)
        ), next_planned AS (
         SELECT DISTINCT ON (succession_plan.zone, succession_plan."position") succession_plan.zone,
            succession_plan."position",
            succession_plan.crop AS next_crop,
            succession_plan.planned_sow
           FROM public.succession_plan
          WHERE ((succession_plan.is_active = true) AND (succession_plan.planned_sow >= CURRENT_DATE))
          ORDER BY succession_plan.zone, succession_plan."position", succession_plan.planned_sow
        )
 SELECT COALESCE(c.zone, n.zone) AS zone,
    COALESCE(c."position", n."position") AS "position",
    c.name AS current_crop,
    c.expected_harvest AS current_harvest_date,
    n.next_crop AS next_planned_crop,
    n.planned_sow AS next_sow_date,
        CASE
            WHEN ((c.expected_harvest IS NOT NULL) AND (n.planned_sow IS NOT NULL)) THEN (n.planned_sow - c.expected_harvest)
            ELSE NULL::integer
        END AS gap_days,
        CASE
            WHEN (c.expected_harvest IS NULL) THEN true
            WHEN (n.planned_sow IS NULL) THEN true
            WHEN ((n.planned_sow - c.expected_harvest) > 7) THEN true
            ELSE false
        END AS gap_flag
   FROM (current_crops c
     FULL JOIN next_planned n ON (((c.zone = n.zone) AND (c."position" = n."position"))));


ALTER VIEW public.v_succession_gaps OWNER TO verdify;

--
-- Name: v_succession_timeline; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_succession_timeline AS
 SELECT 'current'::text AS entry_type,
    c.zone,
    c."position",
    c.name AS crop,
    c.variety,
    c.planted_date AS start_date,
    c.expected_harvest AS end_date,
    c.stage,
    NULL::text AS rotation_group,
    NULL::text AS season
   FROM public.crops c
  WHERE (c.is_active = true)
UNION ALL
 SELECT 'planned'::text AS entry_type,
    s.zone,
    s."position",
    s.crop,
    s.variety,
    s.planned_sow AS start_date,
    s.planned_harvest AS end_date,
    'planned'::text AS stage,
    s.rotation_group,
    s.season
   FROM public.succession_plan s
  WHERE (s.is_active = true)
  ORDER BY 2, 3, 6;


ALTER VIEW public.v_succession_timeline OWNER TO verdify;

--
-- Name: v_target_curve; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_target_curve AS
 SELECT gs AS ts,
    (public.fn_target_band_smooth(gs)).target_temp_min AS target_temp_min,
    (public.fn_target_band_smooth(gs)).target_temp_max AS target_temp_max,
    (public.fn_target_band_smooth(gs)).stress_temp_low AS stress_temp_low,
    (public.fn_target_band_smooth(gs)).stress_temp_high AS stress_temp_high,
    (public.fn_target_band_smooth(gs)).target_vpd_min AS target_vpd_min,
    (public.fn_target_band_smooth(gs)).target_vpd_max AS target_vpd_max,
    (public.fn_target_band_smooth(gs)).stress_vpd_low AS stress_vpd_low,
    (public.fn_target_band_smooth(gs)).stress_vpd_high AS stress_vpd_high,
    (public.fn_target_band_smooth(gs)).target_dli AS target_dli
   FROM generate_series((date_trunc('day'::text, (now() AT TIME ZONE 'America/Denver'::text)) AT TIME ZONE 'America/Denver'::text), ((date_trunc('day'::text, (now() AT TIME ZONE 'America/Denver'::text)) AT TIME ZONE 'America/Denver'::text) + '24:00:00'::interval), '00:05:00'::interval) gs(gs);


ALTER VIEW public.v_target_curve OWNER TO verdify;

--
-- Name: v_water_budget; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_water_budget AS
 SELECT ds.date,
    ds.water_used_gal AS total_gal,
    ds.mister_water_gal AS mister_gal,
    (COALESCE(drip.wall_gal, (0)::double precision) + COALESCE(drip.center_gal, (0)::double precision)) AS drip_gal,
    (((ds.water_used_gal - COALESCE(ds.mister_water_gal, (0)::double precision)) - COALESCE(drip.wall_gal, (0)::double precision)) - COALESCE(drip.center_gal, (0)::double precision)) AS unaccounted_gal,
        CASE
            WHEN (ds.stress_hours_vpd_high > (0)::double precision) THEN round(((COALESCE(ds.mister_water_gal, (0)::double precision) / ds.stress_hours_vpd_high))::numeric, 1)
            ELSE NULL::numeric
        END AS gal_per_vpd_stress_hour
   FROM (public.daily_summary ds
     LEFT JOIN LATERAL ( SELECT ((ds.runtime_drip_wall_h * (60)::double precision) * (2.0)::double precision) AS wall_gal,
            ((ds.runtime_drip_center_h * (60)::double precision) * (2.0)::double precision) AS center_gal) drip ON (true))
  WHERE ((ds.water_used_gal IS NOT NULL) AND (ds.water_used_gal > (0)::double precision));


ALTER VIEW public.v_water_budget OWNER TO verdify;

--
-- Name: VIEW v_water_budget; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_water_budget IS 'Daily water decomposition: mister vs drip vs unaccounted. Includes efficiency metric (gal/VPD stress hour).';


--
-- Name: v_water_daily; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_water_daily AS
 WITH daily_max AS (
         SELECT date_trunc('day'::text, climate.ts) AS day,
            max(climate.water_total_gal) AS day_max
           FROM public.climate
          WHERE ((climate.water_total_gal IS NOT NULL) AND (climate.water_total_gal > (0)::double precision))
          GROUP BY (date_trunc('day'::text, climate.ts))
        )
 SELECT day,
        CASE
            WHEN (day_max < COALESCE(lag(day_max) OVER (ORDER BY day), (0)::double precision)) THEN day_max
            ELSE (day_max - COALESCE(lag(day_max) OVER (ORDER BY day), day_max))
        END AS used_gal
   FROM daily_max d
  ORDER BY day DESC;


ALTER VIEW public.v_water_daily OWNER TO verdify;

--
-- Name: VIEW v_water_daily; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_water_daily IS 'Daily water usage via consecutive-day MAX delta. Handles counter resets gracefully.';


--
-- Name: v_water_efficiency; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_water_efficiency AS
 SELECT date,
    water_used_gal,
    dli_final,
        CASE
            WHEN (dli_final > (0)::double precision) THEN round(((water_used_gal / dli_final))::numeric, 3)
            ELSE NULL::numeric
        END AS gal_per_mol_dli
   FROM public.daily_summary ds
  WHERE (water_used_gal IS NOT NULL)
  ORDER BY date;


ALTER VIEW public.v_water_efficiency OWNER TO verdify;

--
-- Name: v_weekly_summary; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_weekly_summary AS
 SELECT (date_trunc('week'::text, (date)::timestamp with time zone))::date AS week_start,
    ((date_trunc('week'::text, (date)::timestamp with time zone) + '6 days'::interval))::date AS week_end,
    count(*) AS days,
    round((avg(temp_avg))::numeric, 1) AS temp_avg,
    round((min(temp_min))::numeric, 1) AS temp_min,
    round((max(temp_max))::numeric, 1) AS temp_max,
    round((avg(rh_avg))::numeric, 1) AS rh_avg,
    round((min(rh_min))::numeric, 1) AS rh_min,
    round((max(rh_max))::numeric, 1) AS rh_max,
    round((avg(vpd_avg))::numeric, 2) AS vpd_avg,
    round((min(vpd_min))::numeric, 2) AS vpd_min,
    round((max(vpd_max))::numeric, 2) AS vpd_max,
    round((avg(dli_final))::numeric, 1) AS dli_avg,
    round((avg(co2_avg))::numeric, 0) AS co2_avg,
    round((min(outdoor_temp_min))::numeric, 1) AS outdoor_temp_min,
    round((max(outdoor_temp_max))::numeric, 1) AS outdoor_temp_max,
    round((sum(COALESCE(stress_hours_heat, (0)::double precision)))::numeric, 1) AS stress_hours_heat,
    round((sum(COALESCE(stress_hours_cold, (0)::double precision)))::numeric, 1) AS stress_hours_cold,
    round((sum(COALESCE(stress_hours_vpd_high, (0)::double precision)))::numeric, 1) AS stress_hours_vpd_high,
    round((sum(COALESCE(stress_hours_vpd_low, (0)::double precision)))::numeric, 1) AS stress_hours_vpd_low,
    round((sum(COALESCE(water_used_gal, (0)::double precision)))::numeric, 0) AS total_water_gal,
    round((sum(COALESCE(mister_water_gal, (0)::double precision)))::numeric, 0) AS mister_water_gal,
    round((sum(COALESCE(kwh_estimated, (0)::double precision)))::numeric, 1) AS kwh_total,
    round((sum(COALESCE(therms_estimated, (0)::double precision)))::numeric, 2) AS therms_total,
    round((max(COALESCE(peak_kw, (0)::double precision)))::numeric, 2) AS peak_kw,
    round((sum(COALESCE(cost_electric, (0)::double precision)))::numeric, 2) AS cost_electric,
    round((sum(COALESCE(cost_gas, (0)::double precision)))::numeric, 2) AS cost_gas,
    round((sum(COALESCE(cost_water, (0)::double precision)))::numeric, 2) AS cost_water,
    round((sum(COALESCE(cost_total, (0)::double precision)))::numeric, 2) AS total_cost,
    round(((sum(COALESCE(runtime_heat1_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_heat1_h,
    round(((sum(COALESCE(runtime_heat2_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_heat2_h,
    round(((sum(COALESCE((runtime_fan1_min + runtime_fan2_min), (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_fans_h,
    round(((sum(COALESCE(runtime_fog_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_fog_h,
    round(((sum(COALESCE(runtime_vent_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_vent_h,
    round(((sum(COALESCE(runtime_grow_light_min, (0)::double precision)))::numeric / (60)::numeric), 1) AS runtime_grow_light_h,
    round((sum(COALESCE(((runtime_mister_south_h + runtime_mister_west_h) + runtime_mister_center_h), (0)::double precision)))::numeric, 1) AS runtime_misters_h,
    sum((COALESCE(cycles_heat1, 0) + COALESCE(cycles_heat2, 0))) AS cycles_heat,
    sum((COALESCE(cycles_fan1, 0) + COALESCE(cycles_fan2, 0))) AS cycles_fans,
    sum(COALESCE(cycles_fog, 0)) AS cycles_fog,
    sum(COALESCE(cycles_vent, 0)) AS cycles_vent
   FROM public.daily_summary
  WHERE (temp_avg IS NOT NULL)
  GROUP BY (date_trunc('week'::text, (date)::timestamp with time zone))
  ORDER BY ((date_trunc('week'::text, (date)::timestamp with time zone))::date);


ALTER VIEW public.v_weekly_summary OWNER TO verdify;

--
-- Name: VIEW v_weekly_summary; Type: COMMENT; Schema: public; Owner: verdify
--

COMMENT ON VIEW public.v_weekly_summary IS 'ISO week aggregation of daily_summary. Climate averages, stress/water/energy/cost sums, equipment runtime totals.';


--
-- Name: v_zone_temp_delta; Type: VIEW; Schema: public; Owner: verdify
--

CREATE VIEW public.v_zone_temp_delta AS
 SELECT ts,
    (temp_north - temp_south) AS zone_temp_delta
   FROM public.climate
  WHERE ((temp_north IS NOT NULL) AND (temp_south IS NOT NULL));


ALTER VIEW public.v_zone_temp_delta OWNER TO verdify;

